// Merge built-in with custom (custom overrides built-in)
const DOMAIN_REGISTRY = { ...BUILT_IN_DOMAINS, ...customDomains };

// ─────────────────────────────────────────────────────────────────────────
// 2. DOMAIN LOOKUP — exact + parent-domain fallback
// ─────────────────────────────────────────────────────────────────────────
function lookupDomain(domain) {
  if (!domain || domain === 'unknown') return null;
  // 1. Exact match
  if (DOMAIN_REGISTRY[domain]) return { ...DOMAIN_REGISTRY[domain], matchedDomain: domain };
  // 2. Parent domain walk: mail.pfizer.com → pfizer.com
  const parts = domain.split('.');
  for (let i = 1; i < parts.length - 1; i++) {
    const parent = parts.slice(i).join('.');
    if (DOMAIN_REGISTRY[parent]) return { ...DOMAIN_REGISTRY[parent], matchedDomain: parent };
  }
  // 3. TLD pattern — .gov .mil means government
  const tld = parts.slice(-2).join('.');
  if (/\.(gov|mil|gc\.ca|gov\.au|gov\.uk|go\.jp|gouv\.fr|bund\.de)$/.test(domain)) {
    return { cat:'REGULATORY', sub:'GOVERNMENT_GENERIC', tier:'GOVERNMENT', uMult:2.0, riskLevel:2, reg:true, matchedDomain:null, context:'Government domain — regulatory or official authority' };
  }
  if (/\.edu$/.test(domain) || /\.ac\.\w+$/.test(domain)) {
    return { cat:'ACADEMIC', sub:'UNIVERSITY', tier:'ACADEMIC', uMult:1.1, riskLevel:0, matchedDomain:null, context:'Academic institution' };
  }
  return null;
}

// ─────────────────────────────────────────────────────────────────────────
// 3. INTERNAL DOMAIN DETECTION
// ─────────────────────────────────────────────────────────────────────────
function isInternalDomain(domain) {
  if (!domain || !CFG.orgDomain) return false;
  return domain === CFG.orgDomain || domain.endsWith('.' + CFG.orgDomain);
}

// ─────────────────────────────────────────────────────────────────────────
// 4. EMAIL PATTERN CLASSIFICATION
// Detects: HUMAN, DEPARTMENT, AUTOMATED, SYSTEM, BOUNCE
// ─────────────────────────────────────────────────────────────────────────
const EMAIL_PATTERN = {
  HUMAN:       /^[a-z][a-z0-9._%+\-]+@/i,  // firstname.lastname@, j.doe@
  BOUNCE:      /^(mailer.daemon|postmaster|bounce|noreply|no-reply|donotreply|no_reply)@/i,
  AUTOMATED:   /^(noreply|no-reply|donotreply|notifications?|alerts?|updates?|newsletter|digest|auto|automated|system|robot|bot|daemon)@/i,
  DEPARTMENT:  /^(info|hello|support|help|service|billing|accounts?|team|contact|sales|enquir|admin|legal|compliance|hr|finance|marketing|pr|media)@/i,
  TRANSACT:    /^(invoices?|receipts?|orders?|shipping|delivery|confirm|verify|security|password|auth|access|payment)@/i,
};

function classifyEmailPattern(emailAddr) {
  if (!emailAddr) return 'UNKNOWN';
  if (EMAIL_PATTERN.BOUNCE.test(emailAddr))     return 'BOUNCE';
  if (EMAIL_PATTERN.AUTOMATED.test(emailAddr))  return 'AUTOMATED';
  if (EMAIL_PATTERN.TRANSACT.test(emailAddr))   return 'TRANSACTIONAL';
  if (EMAIL_PATTERN.DEPARTMENT.test(emailAddr)) return 'DEPARTMENT';
  // Human pattern: has a dot in local part (j.smith, john.smith) or looks personal
  const local = emailAddr.split('@')[0];
  if (local.includes('.') || local.includes('_')) {
    // Check it's not a department keyword
    if (!EMAIL_PATTERN.DEPARTMENT.test(emailAddr)) return 'HUMAN';
  }
  return 'UNKNOWN';
}

