const TITLE_PATTERNS = {
  C_SUITE: /\b(chief\s+executive|ceo|chief\s+financial|cfo|chief\s+operating|coo|chief\s+technology|cto|chief\s+medical|cmo|chief\s+information|cio|chief\s+compliance|cco|chief\s+revenue|cro|chief\s+marketing|cmo|chairman|chairwoman|chair(?:man|woman|person)?\s+(?:of\s+the\s+board|emeritus)|president\s+(?:and|&)|managing\s+(?:director|partner|principal)|executive\s+(?:director|vice\s+president|evp)|svp|evp|board\s+member|board\s+director|partner\s+(?:at|of|and))\b/i,
  VP:      /\b(vice\s+president|vp(?:\s+of|\s+[\w,]+)?|head\s+of|global\s+head|senior\s+vice\s+president|regional\s+(?:head|vice\s+president|director)|divisional\s+(?:head|director))\b/i,
  DIRECTOR:/\b((?:senior\s+|associate\s+|executive\s+|group\s+|regional\s+|divisional\s+|global\s+)?director(?:\s+of|\s+[\w,]+)?)\b/i,
  MANAGER: /\b((?:senior\s+|junior\s+|associate\s+|project\s+|program\s+|product\s+|account\s+|portfolio\s+)?manager(?:\s+of|\s+[\w,]+)?|team\s+lead(?:er)?|principal\s+(?:[\w\s]+)?(?:analyst|engineer|consultant|architect))\b/i,
};

function detectSenderTier(name, domain, subject, bodySnippet, domainProfile, emailPattern) {
  const signals = [];
  const ctx = [name || '', subject || '', (bodySnippet || '').substring(0, 400)].join(' ');

  // Signal 1: Title regex on name + context
  if (TITLE_PATTERNS.C_SUITE.test(ctx)) signals.push({ tier: 'C_SUITE',   weight: 100 });
  if (TITLE_PATTERNS.VP.test(ctx))      signals.push({ tier: 'VP',        weight: 80 });
  if (TITLE_PATTERNS.DIRECTOR.test(ctx))signals.push({ tier: 'DIRECTOR',  weight: 60 });
  if (TITLE_PATTERNS.MANAGER.test(ctx)) signals.push({ tier: 'MANAGER',   weight: 40 });

  // Signal 2: Domain tier
  if (domainProfile?.tier === 'GOVERNMENT') signals.push({ tier: 'GOVERNMENT_OFFICIAL', weight: 90 });
  if (domainProfile?.tier === 'LEGAL')      signals.push({ tier: 'LEGAL_COUNSEL',       weight: 85 });

  // Signal 3: Email pattern
  if (emailPattern === 'BOUNCE' || emailPattern === 'AUTOMATED') signals.push({ tier: 'AUTOMATED', weight: 200 });
  if (emailPattern === 'DEPARTMENT') signals.push({ tier: 'DEPARTMENT', weight: 50 });

  // Signal 4: Internal domain
  if (isInternalDomain(domain)) signals.push({ tier: 'INTERNAL_STAFF', weight: 30 });

  // Signal 5: Name patterns (Esq., Dr., Hon., Prof.)
  if (/\b(esq\.?|esquire|j\.?d\.?|attorney)\b/i.test(name))   signals.push({ tier: 'LEGAL_COUNSEL',       weight: 70 });
  if (/\b(hon\.?|honourable|judge|justice|magistrate)\b/i.test(name)) signals.push({ tier: 'GOVERNMENT_OFFICIAL', weight: 80 });
  if (/\b(dr\.?|m\.?d\.?|ph\.?d\.?|professor|prof\.?)\b/i.test(name)) signals.push({ tier: 'EXPERT',            weight: 30 });

  // Signal 6: Signature scan — common closing patterns with title
  const sigPattern = /(?:regards?|sincerely|best)\s*,?\s*\n+([^\n]+)\n+([^\n]+)/i;
  const sigMatch = sigPattern.exec(bodySnippet || '');
  if (sigMatch) {
    const sigLine = (sigMatch[1] + ' ' + (sigMatch[2] || ''));
    if (TITLE_PATTERNS.C_SUITE.test(sigLine)) signals.push({ tier: 'C_SUITE',  weight: 80 });
    if (TITLE_PATTERNS.VP.test(sigLine))      signals.push({ tier: 'VP',       weight: 65 });
    if (TITLE_PATTERNS.DIRECTOR.test(sigLine)) signals.push({ tier: 'DIRECTOR',weight: 45 });
  }

  if (signals.length === 0) signals.push({ tier: 'EXTERNAL', weight: 1 });

  // Return highest-weighted tier (resolve conflicts)
  const tierOrder = { AUTOMATED:999, C_SUITE:100, GOVERNMENT_OFFICIAL:90, LEGAL_COUNSEL:85, VP:80, DEPARTMENT:55, DIRECTOR:60, MANAGER:40, EXPERT:35, INTERNAL_STAFF:30, EXTERNAL:1 };
  signals.sort((a, b) => (tierOrder[b.tier] || 0) - (tierOrder[a.tier] || 0));
  return { primary: signals[0].tier, signals };
}

// ─────────────────────────────────────────────────────────────────────────
// 6. VIP DETECTION
// ─────────────────────────────────────────────────────────────────────────
function detectVIP(senderEmail, senderDomain, domainProfile) {
  const emailMatch  = CFG.vipEmails.includes(senderEmail);
  const domainMatch = CFG.vipDomains.includes(senderDomain);
  const forceHigh   = domainProfile?.riskLevel >= 4; // critical-risk domains always VIP-tier behaviour
  return { isVIP: emailMatch || domainMatch || forceHigh, emailMatch, domainMatch };
}

