// ─────────────────────────────────────────────────────────────────────────
// 8. ADVANCED PRELIMINARY SCORING
//
// Score components (additive):
//   Base              50 (neutral starting point)
//   Sender tier       +5 to +45
//   Domain category   +5 to +38
//   Domain risk       +0 to +20
//   VIP               +30
//   Direct TO         +15
//   CC only           -12
//   BCC               -8
//   Urgency keywords  +4 per keyword, capped at +25
//   Critical keywords +10 per keyword, capped at +35
//   Has attachment    +6 (document) or +3 (other)
//   Monetary amount   +8 (suggests financial stakes)
//   Reply chain       -3 per depth over 2, max -15
//   Very short body   -12 (likely automated)
//   Gmail important   +14
//   Gmail starred     +18
//   Promotion label   -30
//   Social label      -20
//   Spam label        -50
//   Email pattern     automated = -40, bounce = -60
//   Boosted domain    +20
//   Is noise          hard-floor 0
//
// Multiplier (applied last):
//   Domain urgency multiplier (0.0–3.0)
//   Result clamped to [0, 100]
// ─────────────────────────────────────────────────────────────────────────
function computePrelimScore(email, domainProfile, tier, isVIP, emailPattern, auditLog) {
  let score = 50; // neutral baseline
  const log = [];

  function add(amount, reason) {
    score += amount;
    log.push(`${reason}(${amount >= 0 ? '+' : ''}${amount})`);
  }

  // ── Sender tier weight ──
  const TIER_WEIGHTS = {
    C_SUITE: 45, VP: 35, DIRECTOR: 22, MANAGER: 12,
    GOVERNMENT_OFFICIAL: 42, LEGAL_COUNSEL: 35,
    DEPARTMENT: 8, EXPERT: 10,
    INTERNAL_STAFF: 5, EXTERNAL: 3,
    AUTOMATED: -40, BOUNCE: -60,
  };
  add(TIER_WEIGHTS[tier] || 3, `tier:${tier}`);

  // ── Domain category weight ──
  const DOM_WEIGHTS = {
    REGULATORY: 38, LEGAL: 32, FINANCIAL: 22, CLIENT: 18,
    CONSULTING: 12, PARTNER: 10, ACADEMIC: 6, INTERNAL: 5,
    AUTOMATED: -40, UNKNOWN: 0,
  };
  const domCat = domainProfile?.cat || (isInternalDomain(email.senderDomain) ? 'INTERNAL' : 'UNKNOWN');
  add(DOM_WEIGHTS[domCat] || 0, `domCat:${domCat}`);

  // ── Domain risk level ──
  if (domainProfile?.riskLevel) {
    const riskBonus = (domainProfile.riskLevel - 1) * 5; // level 2=+5, 3=+10, 4=+15
    if (riskBonus > 0) add(riskBonus, `domRisk:${domainProfile.riskLevel}`);
  }

  // ── VIP ──
  if (isVIP) add(30, 'vip');

  // ── Addressing ──
  if (email.isDirectTO === true)   add(15,  'directTO');
  if (email.isCCOnly   === true)   add(-12, 'ccOnly');
  if (email.isBCC      === true)   add(-8,  'isBCC');

  // ── Urgency signals ──
  const urgKW  = (email.urgencyKeywords  || []);
  const critKW = (email.criticalKeywords || []);
  const urgBonus  = Math.min(urgKW.length  * 4, 25);
  const critBonus = Math.min(critKW.length * 10, 35);
  if (urgBonus > 0)  add(urgBonus,  `urgencyKW:${urgKW.length}`);
  if (critBonus > 0) add(critBonus, `criticalKW:${critKW.length}`);

  // ── Industry-specific critical patterns ──
  const industryCfg = INDUSTRY_CONTEXT[CFG.industry] || INDUSTRY_CONTEXT.GENERAL;
  const bodyLower = (email.bodyText || '').toLowerCase().substring(0, CFG.maxBodyForScoring);
  const subjLower = (email.subject  || '').toLowerCase();
  const combined  = subjLower + ' ' + bodyLower;
  const industryHits = industryCfg.criticalPatterns.filter(p => combined.includes(p));
  if (industryHits.length > 0) add(Math.min(industryHits.length * 8, 24), `industrySignal:${industryHits.length}`);

  // ── Attachment ──
  if (email.hasAttachment) {
    const hasDoc = (email.attachmentTypes || []).some(t => ['DOCUMENT','SPREADSHEET','DATA'].includes(t));
    add(hasDoc ? 6 : 3, `attachment:${hasDoc ? 'doc' : 'other'}`);
  }

  // ── Monetary amount ──
  if (email.hasMonetaryAmount) add(8, 'monetary');

  // ── Reply chain depth ──
  if ((email.threadDepth || 0) > 2) {
    const depthPenalty = Math.min((email.threadDepth - 2) * 3, 15);
    add(-depthPenalty, `replyDepth:${email.threadDepth}`);
  }

  // ── Very short body = likely automated ──
  if ((email.wordCount || 0) < 8) add(-12, 'shortBody');

  // ── Gmail importance signals ──
  if (email.isImportant) add(14, 'gmailImportant');
  if (email.isStarred)   add(18, 'gmailStarred');

  // ── Gmail category labels ──
  if (email.isPromotion) add(-30, 'gmailPromotion');
  if (email.isSocial)    add(-20, 'gmailSocial');
  if (email.isSpam)      add(-50, 'gmailSpam');
  if (email.isUpdates)   add(-10, 'gmailUpdates');
  if (email.isForums)    add(-15, 'gmailForums');

  // ── Email pattern ──
  if (emailPattern === 'AUTOMATED')    add(-40, 'patternAutomated');
  if (emailPattern === 'BOUNCE')       add(-60, 'patternBounce');
  if (emailPattern === 'TRANSACTIONAL')add(-25, 'patternTransact');
  if (emailPattern === 'DEPARTMENT')   add(-5,  'patternDept');

  // ── Boosted domains ──
  if (CFG.boostedDomains.includes(email.senderDomain)) add(20, 'configBoost');

  // ── Apply domain urgency multiplier ──
  const mult = domainProfile?.uMult ?? 1.0;
  if (mult !== 1.0) {
    const before = score;
    score = Math.round(score * mult);
    log.push(`domMult:x${mult}(${before}→${score})`);
  }

  // ── Noise hard-floor ──
  if (email.isLikelyNoise) {
    score = Math.min(score, 5);
    log.push('noiseCap→5');
  }

  return { score: Math.min(100, Math.max(0, score)), log };
}

// ─────────────────────────────────────────────────────────────────────────
// 9. SLA BUCKET PRE-COMPUTATION (heuristic — Claude can override)
// ─────────────────────────────────────────────────────────────────────────
function computeSLAHint(score, domainProfile, critKW, urgKW, isVIP) {
  // Critical regulatory/legal domains → IMMEDIATE
  if (domainProfile?.riskLevel >= 4) return 'IMMEDIATE';
  if (domainProfile?.cat === 'LEGAL' && critKW.length > 0) return 'IMMEDIATE';
  if (isVIP && critKW.length > 0) return 'IMMEDIATE';
  if (score >= 85) return 'IMMEDIATE';
  if (score >= 65) return 'SAME_DAY';
  if (score >= 40) return 'NEXT_DAY';
  if (score >= 15) return 'WEEKLY';
  return 'NONE';
}

// ─────────────────────────────────────────────────────────────────────────
// 10. RISK FLAG AGGREGATION
// Pre-flags emails for legal/regulatory/financial/security review
// ─────────────────────────────────────────────────────────────────────────
function aggregateRiskFlags(email, domainProfile, tier) {
  const body    = (email.bodyText || '').toLowerCase();
  const subject = (email.subject  || '').toLowerCase();
  const ctx     = subject + ' ' + body.substring(0, 1000);

  // Legal flag
  const legalSignals = [
    domainProfile?.legal === true,
    tier === 'LEGAL_COUNSEL',
    /\b(notice of claim|litigation hold|subpoena|cease and desist|without prejudice|privileged|attorney.client|legal action|demand letter|arbitration|injunction|contempt|court order|proceeding|lawsuit|sue|sued|suing)\b/.test(ctx),
    domainProfile?.cat === 'LEGAL',
  ];

  // Regulatory flag
  const regSignals = [
    domainProfile?.reg === true,
    tier === 'GOVERNMENT_OFFICIAL',
    /\b(compliance|regulatory|regulation|audit|inspection|violation|penalty|fine|sanction|enforcement|warning letter|notice of deficiency|corrective action|consent decree|483|subpart)\b/.test(ctx),
  ];

  // Financial flag
  const finSignals = [
    domainProfile?.fin === true,
    email.hasMonetaryAmount,
    /\b(payment|invoice|budget|contract value|purchase order|renewal fee|overdue|past due|collection|write.off|loss|revenue|billing|quote|proposal|pricing)\b/.test(ctx),
  ];

  // Security flag
  const secSignals = [
    email.securityFlag === true,
    /\b(data breach|security incident|unauthorized access|phishing|malware|ransomware|vulnerability|cve|zero.day|credential|password reset|account compromise|suspicious activity|fraud)\b/.test(ctx),
  ];

  return {
    legalFlag:      legalSignals.some(Boolean),
    regulatoryFlag: regSignals.some(Boolean),
    financialFlag:  finSignals.some(Boolean),
    securityFlag:   secSignals.some(Boolean),
  };
}

// ─────────────────────────────────────────────────────────────────────────
// 11. SENDER RELATIONSHIP INTELLIGENCE
// Reads eih_sender_registry data if available via $node
// Falls back to heuristic if DB node not in scope
// ─────────────────────────────────────────────────────────────────────────
function detectRelationship(senderEmail) {
  let registryData = null;
  try {
    const dbResult = $('PostgreSQL Sender Registry Lookup')?.first()?.json;
    if (dbResult?.sender_email) registryData = dbResult;
  } catch(e) { /* no registry node in scope — skip */ }

  if (registryData) {
    return {
      isKnownSender:        true,
      totalEmailsReceived:  registryData.total_emails_received || 0,
      avgUrgencyScore:      registryData.avg_urgency_score || null,
      relationshipStrength: registryData.relationship_strength || 'UNKNOWN',
      lastEmailAt:          registryData.last_email_at || null,
      isFirstContact:       (registryData.total_emails_received || 0) === 0,
      customPriorityBoost:  registryData.custom_priority_boost || 0,
    };
  }

  return {
    isKnownSender:        false,
    totalEmailsReceived:  null,
    avgUrgencyScore:      null,
    relationshipStrength: 'UNKNOWN',
    lastEmailAt:          null,
    isFirstContact:       null,
    customPriorityBoost:  0,
  };
}

// ─────────────────────────────────────────────────────────────────────────
// 12. NOISE DETERMINATION (enhanced with more signal sources)
// ─────────────────────────────────────────────────────────────────────────
function determineNoise(email, domainProfile, emailPattern, score) {
  // Hard noise = automated domain + no urgency signals
  if (domainProfile?.cat === 'AUTOMATED') return { isNoise: true, reason: 'automated_domain' };
  if (email.isSpam) return { isNoise: true, reason: 'spam_label' };
  if (emailPattern === 'BOUNCE') return { isNoise: true, reason: 'bounce_pattern' };
  if (CFG.blockedDomains.includes(email.senderDomain)) return { isNoise: true, reason: 'blocked_domain' };

  // Soft noise — multiple signals, no critical override
  const hasAnyCriticalOverride = (email.criticalKeywords || []).length > 0
    || (email.urgencyKeywords || []).length > 0
    || email.isImportant || email.isStarred;

  if (!hasAnyCriticalOverride) {
    if (email.isPromotion && emailPattern === 'AUTOMATED') return { isNoise: true, reason: 'promotion+automated' };
    if (email.isSocial    && emailPattern !== 'HUMAN')     return { isNoise: true, reason: 'social+non_human' };
    if (emailPattern === 'AUTOMATED' && email.isPromotion) return { isNoise: true, reason: 'automated+promotion' };
  }

  // Score-based floor
  if (score <= 3 && !hasAnyCriticalOverride) return { isNoise: true, reason: 'very_low_score' };

  // Inherit from parse node if already flagged
  if (email.isLikelyNoise) return { isNoise: true, reason: 'parse_node_flag' };

  return { isNoise: false, reason: null };
}

// ═══════════════════════════════════════════════════════════════════════════
// MAIN EXECUTION
// ═══════════════════════════════════════════════════════════════════════════

const auditLog = [];

// Pull from parse node to ensure we have full data
const senderEmail  = (email.senderEmail  || '').toLowerCase();
const senderDomain = (email.senderDomain || 'unknown').toLowerCase();
const senderName   = email.senderName || '';
const subject      = email.subject    || '';
const bodyText     = email.bodyText   || '';

// 1. Domain lookup
const domainProfile = lookupDomain(senderDomain);
auditLog.push(`domainLookup:${domainProfile ? domainProfile.matchedDomain || senderDomain : 'no_match'}`);

// 2. Internal check
const isInternal = isInternalDomain(senderDomain);
auditLog.push(`isInternal:${isInternal}`);

// 3. Email pattern
const emailPattern = classifyEmailPattern(senderEmail);
auditLog.push(`emailPattern:${emailPattern}`);

// 4. VIP check
const { isVIP, emailMatch: vipEmailMatch, domainMatch: vipDomainMatch } = detectVIP(senderEmail, senderDomain, domainProfile);
auditLog.push(`isVIP:${isVIP}(email=${vipEmailMatch},domain=${vipDomainMatch})`);

// 5. Sender tier detection
const { primary: senderTier, signals: tierSignals } = detectSenderTier(
  senderName, senderDomain, subject, bodyText, domainProfile, emailPattern
);
auditLog.push(`senderTier:${senderTier}(${tierSignals.length} signals)`);

// 6. Preliminary score
const { score: prelimScore, log: scoreLog } = computePrelimScore(
  email, domainProfile, senderTier, isVIP, emailPattern, auditLog
);
auditLog.push(`prelimScore:${prelimScore}`);

// 7. SLA hint
const slaBucketHint = computeSLAHint(
  prelimScore, domainProfile, email.criticalKeywords || [], email.urgencyKeywords || [], isVIP
);
auditLog.push(`slaBucketHint:${slaBucketHint}`);

// 8. Risk flags
const riskFlags = aggregateRiskFlags(email, domainProfile, senderTier);
auditLog.push(`riskFlags:legal=${riskFlags.legalFlag},reg=${riskFlags.regulatoryFlag},fin=${riskFlags.financialFlag},sec=${riskFlags.securityFlag}`);

// 9. Noise determination (after scoring)
const { isNoise, reason: noiseReason } = determineNoise(email, domainProfile, emailPattern, prelimScore);
auditLog.push(`isNoise:${isNoise}${noiseReason ? '(' + noiseReason + ')' : ''}`);

// 10. Relationship intelligence
const relationship = detectRelationship(senderEmail);

// 11. Industry context
const industryCfg = INDUSTRY_CONTEXT[CFG.industry] || INDUSTRY_CONTEXT.GENERAL;

// ─────────────────────────────────────────────────────────────────────────
// OUTPUT
// ─────────────────────────────────────────────────────────────────────────
return [{
  json: {
    // ── Pass through all parse node fields ──
    ...email,

    // ── Domain intelligence ──
    domainCategory:      domainProfile?.cat   || (isInternal ? 'INTERNAL' : 'UNKNOWN'),
    domainSubcategory:   domainProfile?.sub   || 'UNKNOWN',
    domainTier:          domainProfile?.tier  || (isInternal ? 'INTERNAL' : 'EXTERNAL'),
    domainUrgencyMult:   domainProfile?.uMult ?? 1.0,
    domainRiskLevel:     domainProfile?.riskLevel ?? 0,
    domainContext:       domainProfile?.context || `Unrecognized domain: ${senderDomain}`,
    domainMatchedOn:     domainProfile?.matchedDomain || null,

    // ── Sender intelligence ──
    senderTier,
    senderTierSignalCount: tierSignals.length,
    emailPattern,
    isInternal,
    isVIP,
    vipEmailMatch,
    vipDomainMatch,
    isBlocked:           CFG.blockedDomains.includes(senderDomain),

    // ── Noise ──
    isLikelyNoise:       isNoise,
    noiseReason,

    // ── Scoring ──
    preliminaryScore:    prelimScore,
    scoreLog,

    // ── SLA hint ──
    slaBucketHint,

    // ── Risk flags (enhanced) ──
    legalFlag:           riskFlags.legalFlag,
    regulatoryFlag:      riskFlags.regulatoryFlag,
    financialFlag:       riskFlags.financialFlag,
    securityFlag:        riskFlags.securityFlag,

    // ── Relationship intelligence ──
    isKnownSender:       relationship.isKnownSender,
    totalEmailsReceived: relationship.totalEmailsReceived,
    avgSenderUrgency:    relationship.avgUrgencyScore,
    relationshipStrength:relationship.relationshipStrength,
    isFirstContact:      relationship.isFirstContact,
    senderPriorityBoost: relationship.customPriorityBoost,

    // ── Industry context (injected into prompt generator) ──
    industryConfig: {
      name:            CFG.industry,
      criticalPatterns: industryCfg.criticalPatterns,
      regulators:       industryCfg.regulators,
      keyTerms:         industryCfg.keyTerms,
      slaOverride:      industryCfg.slaOverride,
    },

    // ── Organization context ──
    orgName:    CFG.orgName,
    orgDomain:  CFG.orgDomain,
    userEmail:  CFG.userEmail,

    // ── Debug ──
    enrichmentAuditLog:  auditLog,
    enrichedAt:          new Date().toISOString(),
    processingStatus:    'ENRICHED',
    pipelineVersion:     '3.0',
  }
}];

