// PARSE CLASSIFICATION RESPONSE — v4.0 ADVANCED
// ─────────────────────────────────────────────────────────────────────────
// Handles every edge case from OpenRouter API responses across all providers:
//   Anthropic, OpenAI, Google, Meta, Mistral, Cohere
//
// Pipeline:
//   1.  Raw HTTP response normalization (fullResponse vs body-only mode)
//   2.  Rate limit & usage header extraction
//   3.  Provider-aware text extraction (handles all content block formats)
//   4.  4-strategy JSON extraction with repair fallback
//   5.  Schema validation + field-level coercion with audit log
//   6.  Hard override rules re-applied post-AI (safety net)
//   7.  SLA computation from classified priority
//   8.  Gmail label generation
//   9.  Risk flag merge (AI result + enrichment engine pre-flags)
//  10.  Confidence routing — low confidence triggers NEEDS-REVIEW label
//  11.  Cost & token accounting
//  12.  Draft routing decision
//  13.  Structured output with full provenance trail
// ═══════════════════════════════════════════════════════════════════════════
// NEW — API response is nested, original fields are at top level
const item         = $input.first().json;


// ─────────────────────────────────────────────────────────────────────────
// 1. RAW HTTP RESPONSE NORMALIZATION
//    n8n HTTP node with fullResponse:true wraps in {body, statusCode, headers}
//    Without fullResponse it returns the body directly
// ─────────────────────────────────────────────────────────────────────────
let responseBody, httpStatus, httpHeaders;

if (item.statusCode !== undefined || item.status !== undefined) {
  // fullResponse mode
  httpStatus  = item.statusCode || item.status || 200;
  httpHeaders = item.headers    || {};
  responseBody = item.body      || {};
} else {
  // body-only mode (older n8n versions or fullResponse:false)
  httpStatus   = 200;
  httpHeaders  = {};
  responseBody = item;
}

// ─────────────────────────────────────────────────────────────────────────
// 2. HEADER EXTRACTION — rate limits, request ID, model used
// ─────────────────────────────────────────────────────────────────────────
const H = (key) => httpHeaders[key] || httpHeaders[key.toLowerCase()] || null;

const rateLimitTotal      = parseInt(H('x-ratelimit-limit-requests')      || H('x-ratelimit-limit')     || '1000');
const rateLimitRemaining  = parseInt(H('x-ratelimit-remaining-requests')  || H('x-ratelimit-remaining') || '999');
const rateLimitResetMs    = H('x-ratelimit-reset-requests') || H('x-ratelimit-reset') || null;
const rateLimitTokens     = parseInt(H('x-ratelimit-remaining-tokens') || '1000000');
const openRouterRequestId = H('x-request-id') || H('cf-ray') || item._requestId || null;
const modelUsedByAPI      = responseBody?.model || item._selectedModel || 'unknown';
const rateLimitNearLimit  = rateLimitRemaining < 10;
const rateLimitCritical   = rateLimitRemaining < 3;

// ─────────────────────────────────────────────────────────────────────────
// 3. TOKEN & USAGE EXTRACTION
//    Works for OpenAI, Anthropic (via OpenRouter), Google formats
// ─────────────────────────────────────────────────────────────────────────
const usage               = responseBody?.usage || {};
const actualInputTokens   = usage.prompt_tokens      || usage.input_tokens        || item._totalInputTokensEst || 0;
const actualOutputTokens  = usage.completion_tokens  || usage.output_tokens       || 0;
const actualCacheRead     = usage.cache_read_input_tokens                          || 0;
const actualCacheWrite    = usage.cache_creation_input_tokens                     || 0;
const actualTotalTokens   = usage.total_tokens || (actualInputTokens + actualOutputTokens);

// Cost computation — per model rates
const MODEL_RATES = {
  'anthropic/claude-sonnet-4-5':       { inp: 3.00,   out: 15.00,  cacheR: 0.30,  cacheW: 3.75  },
  'anthropic/claude-opus-4-5':         { inp: 15.00,  out: 75.00,  cacheR: 1.50,  cacheW: 18.75 },
