  'meta-llama/llama-3.3-70b-instruct': { inp: 0.20,   out: 0.20,   cacheR: 0,     cacheW: 0     },
  'mistralai/mistral-large':           { inp: 2.00,   out: 6.00,   cacheR: 0,     cacheW: 0     },
};

const rates = MODEL_RATES[modelUsedByAPI] || MODEL_RATES[item._selectedModel] || { inp: 0, out: 0, cacheR: 0, cacheW: 0 };
const actualCostUSD =
  (actualInputTokens   / 1_000_000 * rates.inp)  +
  (actualOutputTokens  / 1_000_000 * rates.out)  +
  (actualCacheRead     / 1_000_000 * rates.cacheR)+
  (actualCacheWrite    / 1_000_000 * rates.cacheW);

// ─────────────────────────────────────────────────────────────────────────
// 4. PROVIDER-AWARE CONTENT EXTRACTION
//    OpenRouter normalizes to OpenAI format but response quirks vary
// ─────────────────────────────────────────────────────────────────────────
function extractRawText(resp) {
  if (!resp) return '';

  // OpenAI / OpenRouter standard (all providers via OR)
  const choice = resp.choices?.[0];
  if (choice) {
    const msg = choice.message || choice.delta || {};
    if (typeof msg.content === 'string')    return msg.content;
    // Anthropic native content blocks (if routed directly)
    if (Array.isArray(msg.content)) {
      return msg.content
        .filter(b => b.type === 'text')
        .map(b => b.text)
        .join('');
    }
  }

  // Anthropic native API format (legacy)
  if (resp.content && Array.isArray(resp.content)) {
    return resp.content.filter(b => b.type === 'text').map(b => b.text).join('');
  }

  // Google Gemini native (if bypassing OR)
  if (resp.candidates?.[0]?.content?.parts) {
    return resp.candidates[0].content.parts.map(p => p.text || '').join('');
  }

  // Direct text field
  if (typeof resp.text === 'string')    return resp.text;
  if (typeof resp.content === 'string') return resp.content;

  // Last resort — stringify and try to find JSON
  return JSON.stringify(resp);
}

const rawText = extractRawText(responseBody);

// Capture finish reason for quality assessment
const finishReason = responseBody?.choices?.[0]?.finish_reason || 'unknown';
const wasMaxTokensCut = finishReason === 'length';

// ─────────────────────────────────────────────────────────────────────────
// 5. 4-STRATEGY JSON EXTRACTION WITH REPAIR
// ─────────────────────────────────────────────────────────────────────────
function extractJSON(text) {
  if (!text || typeof text !== 'string') return { result: null, strategy: 'none', repaired: false };

  // Strategy 1: Direct parse after stripping markdown fences
  const stripped = text
    .replace(/^```json\s*/im, '').replace(/^```\s*/im, '').replace(/\s*```\s*$/im, '')
    .trim();
  try {
    return { result: JSON.parse(stripped), strategy: 'direct', repaired: false };
  } catch(e1) {}

  // Strategy 2: Extract outermost complete JSON object
  const start = text.indexOf('{');
  const end   = text.lastIndexOf('}');
  if (start !== -1 && end > start) {
    try {
      return { result: JSON.parse(text.substring(start, end + 1)), strategy: 'bracket_extract', repaired: false };
    } catch(e2) {}
  }

  // Strategy 3: Regex — largest JSON-looking block
  const jsonBlocks = text.match(/\{[\s\S]*\}/g) || [];
  for (const block of jsonBlocks.sort((a, b) => b.length - a.length)) {
    try {
      return { result: JSON.parse(block), strategy: 'regex_largest', repaired: false };
    } catch(e3) {}
  }

  // Strategy 4: Repair common AI JSON mistakes
  let repairAttempt = text.substring(start >= 0 ? start : 0, end >= 0 ? end + 1 : text.length);
  // Fix: trailing commas before } or ]
  repairAttempt = repairAttempt.replace(/,\s*([}\]])/g, '$1');
  // Fix: single-quoted strings
  repairAttempt = repairAttempt.replace(/'/g, '"');
  // Fix: unquoted boolean-like values
  repairAttempt = repairAttempt.replace(/:\s*True\b/g, ': true').replace(/:\s*False\b/g, ': false').replace(/:\s*None\b/g, ': null');
  // Fix: line breaks in string values (common Anthropic quirk)
  repairAttempt = repairAttempt.replace(/("(?:[^"\\]|\\.)*")|(\n)/g, (m, str) => str ? str : ' ');
  try {
    return { result: JSON.parse(repairAttempt), strategy: 'repair', repaired: true };
  } catch(e4) {}

  return { result: null, strategy: 'failed', repaired: false };
}

const { result: classified, strategy: extractStrategy, repaired: wasRepaired } = extractJSON(rawText);
const parseError = classified ? null : `JSON extraction failed (4 strategies attempted). Model: ${modelUsedByAPI}. Finish reason: ${finishReason}. Raw length: ${rawText.length}`;

let c = classified || {};

// ─────────────────────────────────────────────────────────────────────────
// 6. VALIDATION ENUM SETS
// ─────────────────────────────────────────────────────────────────────────
const VALID = {
  PRIORITY:  new Set(['CRITICAL','HIGH','MEDIUM','LOW','NOISE']),
  SLA:       new Set(['IMMEDIATE','SAME_DAY','NEXT_DAY','WEEKLY','NONE']),
  INTENT:    new Set(['ACTION_REQUIRED','APPROVAL','FYI','MEETING','CONTRACT','COMPLAINT',
                      'ESCALATION','LEGAL_NOTICE','INTRODUCTION','PAYMENT','AUDIT','INSPECTION','NEGOTIATION','OTHER']),
  SENTIMENT: new Set(['POSITIVE','NEUTRAL','CONCERNED','URGENT','NEGATIVE','THREATENING','FORMAL']),
  TIER:      new Set(['C_SUITE','VP','DIRECTOR','MANAGER','GOVERNMENT_OFFICIAL',
                      'LEGAL_COUNSEL','DEPARTMENT','INTERNAL_STAFF','EXTERNAL']),
  DOM_CAT:   new Set(['REGULATORY','LEGAL','FINANCIAL','CLIENT','CONSULTING',
                      'PARTNER','INTERNAL','AUTOMATED','ACADEMIC','UNKNOWN']),
  RISK:      new Set(['CRITICAL','HIGH','MEDIUM','LOW','NONE']),
};

function coerce(val, validSet, fallback) {
  const v = typeof val === 'string' ? val.toUpperCase().trim() : '';
  return validSet.has(v) ? v : fallback;
}

function safeArr(val) {
  if (Array.isArray(val)) return val.filter(v => v != null);
  if (val == null || val === '') return [];
  if (typeof val === 'string') return [val];
  return [String(val)];
}

function safeBool(val, def = false) {
  if (typeof val === 'boolean') return val;
  if (val === 'true'  || val === 1) return true;
  if (val === 'false' || val === 0) return false;
  return def;
}

function safeFloat(val, def, min, max) {
  const n = parseFloat(val);
  if (isNaN(n)) return def;
  return Math.min(max, Math.max(min, n));
}

function safeInt(val, def, min, max) {
  const n = parseInt(val);
  if (isNaN(n)) return def;
  return Math.min(max, Math.max(min, n));
}

// ─────────────────────────────────────────────────────────────────────────
// 7. FIELD EXTRACTION WITH COERCION AUDIT
// ─────────────────────────────────────────────────────────────────────────
const coercionLog = [];
function withAudit(field, computed, original) {
  if (original !== computed && original !== undefined) {
    coercionLog.push(`${field}: "${original}" → "${computed}"`);
  }
  return computed;
}

// Fallback priority from preliminary score (if AI fails)
const scoreFallback = (item.preliminaryScore || 0) >= 80 ? 'HIGH'
                    : (item.preliminaryScore || 0) >= 55 ? 'MEDIUM'
                    : (item.preliminaryScore || 0) >= 25 ? 'LOW' : 'NOISE';

const priority   = withAudit('priority_class', coerce(c.priority_class, VALID.PRIORITY, scoreFallback), c.priority_class);
const intent     = withAudit('intent',         coerce(c.intent,         VALID.INTENT,   'OTHER'),       c.intent);
const sentiment  = withAudit('sentiment',      coerce(c.sentiment,      VALID.SENTIMENT,'NEUTRAL'),     c.sentiment);
const senderTier = withAudit('sender_tier',    coerce(c.sender_tier,    VALID.TIER,     item.senderTier || 'EXTERNAL'), c.sender_tier);
const domCat     = withAudit('domain_category',coerce(c.domain_category,VALID.DOM_CAT,  item.domainCategory || 'UNKNOWN'), c.domain_category);
const domSub     = c.domain_subcategory || item.domainSubcategory || 'UNKNOWN';

const urgencyScore    = withAudit('urgency_score',    safeInt(c.urgency_score,    5, 1, 10), c.urgency_score);
