function applyOverride(newPriority, reason) {
  const ORDER = { CRITICAL:0, HIGH:1, MEDIUM:2, LOW:3, NOISE:4 };
  if (ORDER[newPriority] < ORDER[finalPriority]) {
    overrideLog.push(`${finalPriority} → ${newPriority} (${reason})`);
    finalPriority = newPriority;
  }
}

// Re-apply from enrichment engine pre-flags
if (item.regulatoryFlag || item.legalFlag)                    applyOverride('CRITICAL', 'regulatory/legal flag');
if (item.domainRiskLevel >= 4)                                applyOverride('CRITICAL', 'domain risk level 4');
if (['REGULATORY','LEGAL'].includes(item.domainCategory))     applyOverride('HIGH',     'regulatory/legal domain');
if (item.isVIP && urgencyScore >= 6)                          applyOverride('HIGH',     'vip + urgency ≥6');
if ((item.criticalKeywords || []).length > 0)                 applyOverride('HIGH',     'critical keywords detected');
if (item.securityFlag)                                        applyOverride('CRITICAL', 'security incident flag');
if (item.financialFlag && (item.preliminaryScore||0) >= 70)   applyOverride('HIGH',     'financial flag + high score');
if (safeBool(c.regulatory_flag) || safeBool(c.legal_flag))    applyOverride('CRITICAL', 'AI detected regulatory/legal');
if (safeBool(c.security_flag))                                applyOverride('CRITICAL', 'AI detected security incident');
