// Escalation target: use AI suggestion, or derive from priority + domain
const escalateTo = c.escalate_to
  || (regulatoryFlag    ? 'VP Regulatory Affairs + General Counsel'  : null)
  || (legalFlag         ? 'General Counsel'                          : null)
  || (securityFlag      ? 'CISO + IT Security'                       : null)
  || (financialFlag && finalPriority === 'CRITICAL' ? 'CFO + Treasury' : null)
  || (finalPriority === 'CRITICAL' ? 'Direct Manager + Relevant Department Head' : null);

// ─────────────────────────────────────────────────────────────────────────
// 11. STRUCTURED FIELD EXTRACTION
// ─────────────────────────────────────────────────────────────────────────

// Action items — normalize to object array
function normalizeActionItems(raw) {
  const arr = safeArr(raw);
  return arr.map(item => {
    if (typeof item === 'string') return { action: item, owner: null, deadline: null, priority: 'NORMAL' };
    if (typeof item === 'object' && item.action) return item;
    return { action: String(item), owner: null, deadline: null, priority: 'NORMAL' };
  }).filter(a => a.action && a.action.length > 2);
}

// Deadlines — normalize to object array with consequence
function normalizeDeadlines(raw) {
  const arr = safeArr(raw);
  return arr.map(d => {
    if (typeof d === 'string') return { description: d, date: null, is_hard: false, consequence: null };
    return {
      description: d.description || d.desc || String(d),
      date:        d.date        || d.deadline || null,
      is_hard:     safeBool(d.is_hard, false),
      consequence: d.consequence || null,
    };
  }).filter(d => d.description && d.description.length > 2);
}

// Stakeholders — normalize to object array
function normalizeStakeholders(raw) {
  const arr = safeArr(raw);
  return arr.map(s => {
    if (typeof s === 'string') return { name: s, role: null, organization: null };
    return {
      name:         s.name         || null,
      role:         s.role         || null,
      organization: s.organization || s.org || null,
    };
  }).filter(s => s.name && s.name.length > 1);
}

const actionItems     = normalizeActionItems(c.action_items);
const keyDeadlines    = normalizeDeadlines(c.key_deadlines);
const keyStakeholders = normalizeStakeholders(c.key_stakeholders);
const monetaryAmounts = safeArr(c.monetary_amounts).filter(m => typeof m === 'string' && m.length > 0);
const referenceNumbers= safeArr(c.reference_numbers).filter(r => typeof r === 'string' && r.length > 0);
const suggestedLabels = safeArr(c.suggested_labels).filter(l => typeof l === 'string');

// Key quote validation — must be a non-empty string, not fabricated
const rawKeyQuote = c.key_quote;
const keyQuote = (typeof rawKeyQuote === 'string' && rawKeyQuote.length > 4 && rawKeyQuote.length <= 300)
  ? rawKeyQuote
  : null;

// Summary quality check
const emailSummary = (typeof c.email_summary === 'string' && c.email_summary.length > 10)
  ? c.email_summary
  : item.subject || '(No summary generated)';

const classificationReason = (typeof c.classification_reason === 'string' && c.classification_reason.length > 5)
  ? c.classification_reason
  : `${finalPriority} — preliminary score: ${item.preliminaryScore}/100, domain: ${domCat}`;

const lowConfidenceReason = confidenceScore < 0.70
  ? (c.low_confidence_reason || `Confidence below threshold (${(confidenceScore*100).toFixed(0)}%)`)
  : null;

// ─────────────────────────────────────────────────────────────────────────
// 12. GMAIL LABEL GENERATION
// ─────────────────────────────────────────────────────────────────────────
const PRIORITY_LABELS = {
  CRITICAL:'EIH/CRITICAL', HIGH:'EIH/HIGH', MEDIUM:'EIH/MEDIUM', LOW:'EIH/LOW', NOISE:'EIH/NOISE',
};
const DOMAIN_LABELS = {
  REGULATORY:'EIH/REGULATORY', LEGAL:'EIH/LEGAL', FINANCIAL:'EIH/FINANCIAL',
  CLIENT:'EIH/CLIENT', INTERNAL:'EIH/INTERNAL', SECURITY:'EIH/SECURITY',
};

const gmailLabels = [
  PRIORITY_LABELS[finalPriority],
  DOMAIN_LABELS[domCat]                    || null,
  legalFlag                                ? 'EIH/LEGAL-FLAG'        : null,
  regulatoryFlag                           ? 'EIH/REGULATORY-FLAG'   : null,
  securityFlag                             ? 'EIH/SECURITY-FLAG'     : null,
  financialFlag                            ? 'EIH/FINANCIAL-FLAG'    : null,
  confidenceScore < 0.70                   ? 'EIH/NEEDS-REVIEW'      : null,
  privilegeFlag                            ? 'EIH/PRIVILEGED'        : null,
  preservationReq                          ? 'EIH/PRESERVE-DOCS'     : null,
  escalation && finalPriority === 'CRITICAL'? 'EIH/ESCALATE'         : null,
  slaBreach                                ? 'EIH/SLA-BREACH'        : null,
  wasMaxTokensCut                          ? 'EIH/TRUNCATED-RESPONSE': null,
  item.isLikelyNoise                       ? 'EIH/NOISE'             : null,
].filter(Boolean);

// ─────────────────────────────────────────────────────────────────────────
// 13. DRAFT ROUTING DECISION
// ─────────────────────────────────────────────────────────────────────────
const replyRequired = c.reply_required !== false;
const replyUrgency  = coerce(c.reply_urgency, VALID.SLA, finalSla);

const shouldDraft = replyRequired
  && finalPriority !== 'NOISE'
  && intent         !== 'FYI'
  && finalSla        !== 'NONE'
  && !item.isBCC
  && !item.isLikelyNoise;

// ─────────────────────────────────────────────────────────────────────────
// 14. LANGUAGE & TRANSLATION
// ─────────────────────────────────────────────────────────────────────────
const language         = c.language || item.language || 'en';
const requiresTranslation = safeBool(c.requires_translation) || (language !== 'en' && item.wordCount > 20);

// ─────────────────────────────────────────────────────────────────────────
// 15. QUALITY ASSESSMENT
// ─────────────────────────────────────────────────────────────────────────
const qualityFlags = [];
if (parseError)                          qualityFlags.push('PARSE_FAILED');
if (wasRepaired)                         qualityFlags.push('JSON_REPAIRED');
if (wasMaxTokensCut)                     qualityFlags.push('RESPONSE_TRUNCATED');
if (coercionLog.length > 3)              qualityFlags.push('MANY_COERCIONS');
if (overrideLog.length > 0)             qualityFlags.push('HARD_OVERRIDE_APPLIED');
if (confidenceScore < 0.50)             qualityFlags.push('LOW_CONFIDENCE');
if (confidenceScore < 0.70)             qualityFlags.push('BELOW_CONFIDENCE_THRESHOLD');
if (modelUsedByAPI !== item._selectedModel) qualityFlags.push('PROVIDER_FALLBACK_USED');
if (!classified)                         qualityFlags.push('FALLBACK_TO_HEURISTIC');

const overallQuality = qualityFlags.length === 0 ? 'CLEAN'
  : qualityFlags.includes('PARSE_FAILED') ? 'FAILED'
  : qualityFlags.includes('HARD_OVERRIDE_APPLIED') ? 'OVERRIDDEN'
  : qualityFlags.includes('JSON_REPAIRED') || qualityFlags.includes('MANY_COERCIONS') ? 'REPAIRED'
  : 'DEGRADED';

// ─────────────────────────────────────────────────────────────────────────
// 16. FINAL OUTPUT
// ─────────────────────────────────────────────────────────────────────────
return [{ json: {
  // ── Original email identity (pass-through) ──
  messageId:                  item.messageId,
  threadId:                   item.threadId,
  senderName:                 item.senderName,
  senderEmail:                item.senderEmail,
  senderDomain:               item.senderDomain,
  subject:                    item.subject,
  bodyText:                   item.bodyText,
  receivedAt:                 item.receivedAt,
  source:                     item.source,
  hasAttachment:              item.hasAttachment,
  attachments:                item.attachments,
  attachmentTypes:            item.attachmentTypes,
  attachmentNames:            item.attachmentNames,
  isVIP:                      item.isVIP,
  isInternal:                 item.isInternal,
  isDirectTO:                 item.isDirectTO,
  isCCOnly:                   item.isCCOnly,
