  readingTimeSeconds:         item.readingTimeSeconds,
  threadDepth:                item.threadDepth,
  isReply:                    item.isReply,
  isForward:                  item.isForward,
  phoneNumbers:               item.phoneNumbers,
  domainContext:              item.domainContext,
  domainRiskLevel:            item.domainRiskLevel,
  domainUrgencyMult:          item.domainUrgencyMult,
  domainMatchedOn:            item.domainMatchedOn,
  isKnownSender:              item.isKnownSender,
  relationshipStrength:       item.relationshipStrength,
  isFirstContact:             item.isFirstContact,
  emailPattern:               item.emailPattern,
  enrichmentAuditLog:         item.enrichmentAuditLog,

  // ── AI Classification results (final, post-override) ──
  priorityClass:              finalPriority,
  priorityClassRaw:           priority,          // before override
  urgencyScore,
  confidenceScore,
  slaBucket:                  finalSla,
  slaBucketRaw:               aiSla,             // before consistency check
  slaHours,
  slaDeadline,
  slaBreach,
  domainCategory:             domCat,
  domainSubcategory:          domSub,
  senderTier,
  intent,
  sentiment,
  replyRequired,
  replyUrgency,
  language,
  requiresTranslation,

  // ── Extracted intelligence ──
  actionItems,
  keyDeadlines,
  keyStakeholders,
  monetaryAmounts,
  referenceNumbers,
  suggestedLabels,
  emailSummary,
  classificationReason,
  lowConfidenceReason,
  keyQuote,

  // ── Risk flags (merged: AI + enrichment) ──
  financialFlag,
  legalFlag,
  regulatoryFlag,
  securityFlag,
  hrFlag,
  escalationRecommended:      escalation,
  escalateTo,
  privilegeFlag,
  preservationRequired:       preservationReq,
  boardNotificationRequired:  boardNotifReq,
  externalCounselRequired:    extCounselReq,
  publicDisclosureRisk:       pubDisclosureRisk,
  counterpartyRiskLevel:      coerce(c.counterparty_risk_level, VALID.RISK, 'NONE'),

  // Extended regulatory fields (high-stakes only)
  regulatoryBody:             c.regulatory_body      || null,
  regulatoryFramework:        c.regulatory_framework || null,
  jurisdiction:               c.jurisdiction         || null,
  repeatIssue:                c.repeat_issue         || null,

  // ── Gmail labels ──
  gmailLabels,

  // ── Routing ──
  shouldDraft,

  // ── API provenance ──
  apiModel:                   modelUsedByAPI,
  apiModelRequested:          item._selectedModel,
  apiProvider:                item._selectedProvider,
  apiRoutingTier:             item._routingTier,
  apiFinishReason:            finishReason,
  apiInputTokens:             actualInputTokens,
  apiOutputTokens:            actualOutputTokens,
  apiCacheReadTokens:         actualCacheRead,
  apiCacheWriteTokens:        actualCacheWrite,
  apiTotalTokens:             actualTotalTokens,
  apiCostUSD:                 Math.round(actualCostUSD * 1_000_000) / 1_000_000,
  apiEstimatedCostUSD:        item._estimatedCostUSD,
  apiBodyWasTruncated:        item._bodyWasTruncated || false,
  requestId:                  openRouterRequestId || item._requestId,

  // ── Rate limit state ──
  rateLimitTotal,
  rateLimitRemaining,
  rateLimitTokens,
  rateLimitNearLimit,
  rateLimitCritical,
  rateLimitResetMs,

  // ── Parse quality ──
  parseError,
  parseStrategy:              extractStrategy,
  wasRepaired,
  wasMaxTokensCut,
  coercionLog,
  overrideLog,
  qualityFlags,
  overallQuality,

  // ── Timestamps ──
  classifiedAt:               new Date().toISOString(),
  processingStatus:           'CLASSIFIED',
  pipelineVersion:            '4.0',
}}];

// ═══════════════════════════════════════════════════════════════════════════
// DYNAMIC REPLY PROMPT GENERATOR — v4.0 ADVANCED
// ─────────────────────────────────────────────────────────────────────────
// Builds hyper-personalised system + user prompts for AI reply drafting.
// Every prompt is calibrated to: sender tier, domain category, industry,
// priority class, intent, sentiment, risk flags, and relationship history.
//
// Architecture:
//   1.  Config loading + environment resolution
//   2.  Voice profile library (8 registers × 3 formality levels)
//   3.  Domain-specific reply protocols (9 categories)
//   4.  Intent-specific reply frameworks (14 intents)
//   5.  Industry reply intelligence (13 industries)
//   6.  Tone calibration from sentiment + relationship strength
//   7.  Structural scaffolding (opening, body, closing, signature)
//   8.  Placeholder strategy (NEEDS INPUT vs VERIFY vs WARNING)
//   9.  Legal / regulatory / financial guard rails
//  10.  Adaptive length targeting
//  11.  Few-shot calibration examples (domain + intent combinations)
//  12.  Anti-patterns library (things Claude must never write)
//  13.  System prompt assembly
//  14.  User prompt assembly with full email context
//  15.  Output schema (JSON reply object)
// ═══════════════════════════════════════════════════════════════════════════

const email = $input.first().json;

// ─────────────────────────────────────────────────────────────────────────
