// ─────────────────────────────────────────────────────────────────────────
// 3. FORMALITY LEVEL SELECTION
//    Based on domain category, sender tier, sentiment, and relationship
// ─────────────────────────────────────────────────────────────────────────
function selectFormality() {
  // Always formal
  if (['GOVERNMENT_OFFICIAL','LEGAL_COUNSEL'].includes(senderTier)) return 'formal';
  if (['REGULATORY','LEGAL'].includes(domCat))                       return 'formal';
  if (['THREATENING','FORMAL'].includes(sentiment))                  return 'formal';
  if (priority === 'CRITICAL' && !isInternal)                       return 'formal';

  // Warm if established relationship + internal or known
  if (isInternal && ['HIGH','MEDIUM','LOW'].includes(priority))      return 'warm';
  if (isKnown && relStrength === 'HIGH' && !legalFlag && !regFlag)   return 'warm';
  if (['INTERNAL_STAFF'].includes(senderTier))                       return 'warm';

  return 'standard';
}

const formality  = selectFormality();
const tierKey    = ['C_SUITE','VP','DIRECTOR','MANAGER','GOVERNMENT_OFFICIAL','LEGAL_COUNSEL','INTERNAL_STAFF'].includes(senderTier)
  ? senderTier : 'EXTERNAL';
const voiceSpec  = (VOICE[tierKey] || VOICE['EXTERNAL'])[formality] || VOICE['EXTERNAL']['standard'];

// ─────────────────────────────────────────────────────────────────────────
// 4. DOMAIN-SPECIFIC REPLY PROTOCOLS
// ─────────────────────────────────────────────────────────────────────────
const DOMAIN_PROTOCOLS = {

  REGULATORY: `
REGULATORY REPLY PROTOCOL — CRITICAL RULES:
• Acknowledge receipt formally and immediately — do NOT delay
• Reference the EXACT document title, reference number, docket ID, and date from the email
• State clearly who is the responsible owner of the response process internally
• Do NOT make substantive positions, commitments, or promises about outcomes
• Do NOT admit fault, concede deficiencies, or confirm alleged violations
• If a response deadline is stated — acknowledge it explicitly and confirm intent to meet it
• ALL outgoing correspondence to regulators must be reviewed by authorized regulatory counsel before sending
• Include the mandatory legal review warning: [WARNING: REGULATORY CORRESPONDENCE — MUST BE REVIEWED BY REGULATORY COUNSEL AND LEGAL BEFORE DISPATCH]
• Tone: measured, professional, cooperative — never adversarial, never dismissive`,

  LEGAL: `
LEGAL REPLY PROTOCOL — CRITICAL RULES:
• Acknowledge receipt of the communication — DO NOT engage substantively
