function selectExamples() {
  const key = `${domCat}_${intent}`;
  const examples = [];

  if (FEW_SHOT[key])                          examples.push(FEW_SHOT[key]);
  if (FEW_SHOT[`${domCat}_LEGAL_NOTICE`] && legalFlag && !examples.includes(FEW_SHOT[`${domCat}_LEGAL_NOTICE`]))
                                              examples.push(FEW_SHOT[`${domCat}_LEGAL_NOTICE`]);
  if (examples.length === 0) {
    if (domCat === 'REGULATORY')              examples.push(FEW_SHOT['REGULATORY_LEGAL_NOTICE']);
    else if (domCat === 'CLIENT')             examples.push(FEW_SHOT['CLIENT_ESCALATION']);
    else if (domCat === 'LEGAL')              examples.push(FEW_SHOT['LEGAL_LEGAL_NOTICE']);
    else if (domCat === 'FINANCIAL')          examples.push(FEW_SHOT['FINANCIAL_ACTION_REQUIRED']);
    else if (domCat === 'INTERNAL')           examples.push(FEW_SHOT['INTERNAL_ACTION_REQUIRED']);
  }

  return examples.slice(0, 2).join('\n\n---\n\n');
}

