// ═══════════════════════════════════════════════════════════════════════════
// PARSE REPLY DRAFT RESPONSE — v4.0 ADVANCED
// ─────────────────────────────────────────────────────────────────────────
// Handles every edge case from OpenRouter reply draft responses:
//
// Pipeline:
//   1.  HTTP response normalization (fullResponse vs body-only)
//   2.  Provider-aware text extraction (5 formats)
//   3.  4-strategy JSON extraction with repair
//   4.  Draft text validation and sanitization
//   5.  Placeholder analysis ([NEEDS INPUT], [VERIFY], [WARNING])
//   6.  Quality scoring (8-signal composite)
//   7.  Structural analysis (salutation, body, closing, signature)
//   8.  Legal/regulatory compliance check
//   9.  Commitment extraction (what was promised, to whom, by when)
//  10.  Anti-pattern detection (prohibited phrases check)
//  11.  Tone and register validation
//  12.  Fallback draft generation (when AI fails)
//  13.  Token + cost accounting
//  14.  Draft readiness routing
//  15.  Structured output with full audit trail
// ═══════════════════════════════════════════════════════════════════════════

const item = $input.first().json;

// ─────────────────────────────────────────────────────────────────────────
// 1. HTTP RESPONSE NORMALIZATION
// ─────────────────────────────────────────────────────────────────────────
let responseBody, httpStatus, httpHeaders;

if (item.statusCode !== undefined || item.status !== undefined) {
  httpStatus   = item.statusCode || item.status || 200;
  httpHeaders  = item.headers    || {};
  responseBody = item.body       || {};
} else {
  httpStatus   = 200;
  httpHeaders  = {};
  responseBody = item;
}

// ─────────────────────────────────────────────────────────────────────────
// 2. PROVIDER-AWARE TEXT EXTRACTION
// ─────────────────────────────────────────────────────────────────────────
function extractRawText(resp) {
  if (!resp) return '';
  // OpenAI / OpenRouter standard
  const choice = resp.choices?.[0];
  if (choice) {
    const msg = choice.message || choice.delta || {};
    if (typeof msg.content === 'string') return msg.content;
    if (Array.isArray(msg.content))
      return msg.content.filter(b => b.type === 'text').map(b => b.text).join('');
  }
  // Anthropic native content blocks
  if (Array.isArray(resp.content))
    return resp.content.filter(b => b.type === 'text').map(b => b.text).join('');
  // Google Gemini
  if (resp.candidates?.[0]?.content?.parts)
    return resp.candidates[0].content.parts.map(p => p.text || '').join('');
  // Direct fields
  if (typeof resp.text    === 'string') return resp.text;
  if (typeof resp.content === 'string') return resp.content;
  return JSON.stringify(resp);
}

const rawText      = extractRawText(responseBody);
const finishReason = responseBody?.choices?.[0]?.finish_reason || 'unknown';
const wasCut       = finishReason === 'length';

// ─────────────────────────────────────────────────────────────────────────
// 3. 4-STRATEGY JSON EXTRACTION WITH REPAIR
// ─────────────────────────────────────────────────────────────────────────
function extractJSON(text) {
  if (!text || typeof text !== 'string')
    return { result: null, strategy: 'none', repaired: false };

  // Strategy 1: strip markdown fences + direct parse
  const s1 = text
    .replace(/^```json\s*/im, '').replace(/^```\s*/im, '')
    .replace(/\s*```\s*$/im, '').trim();
  try { return { result: JSON.parse(s1), strategy: 'direct', repaired: false }; }
  catch(e) {}

  // Strategy 2: outermost { }
  const si = text.indexOf('{'), se = text.lastIndexOf('}');
  if (si !== -1 && se > si) {
    try { return { result: JSON.parse(text.substring(si, se + 1)), strategy: 'bracket', repaired: false }; }
    catch(e) {}
  }

  // Strategy 3: largest JSON block via regex
  for (const block of (text.match(/\{[\s\S]*?\}/g) || []).sort((a,b) => b.length - a.length)) {
    try { return { result: JSON.parse(block), strategy: 'regex', repaired: false }; }
    catch(e) {}
  }

  // Strategy 4: repair common AI JSON defects
  let rep = text.substring(si >= 0 ? si : 0, se >= 0 ? se + 1 : text.length);
  rep = rep
    .replace(/,\s*([}\]])/g, '$1')                          // trailing commas
    .replace(/([{,]\s*)(\w+)\s*:/g, '$1"$2":')              // unquoted keys
    .replace(/:\s*'([^']*)'/g, ': "$1"')                    // single-quoted values
    .replace(/:\s*True\b/g,  ': true')                      // Python booleans
    .replace(/:\s*False\b/g, ': false')
    .replace(/:\s*None\b/g,  ': null')
    .replace(/("(?:[^"\\]|\\.)*")|(\n)/g,                   // line breaks inside strings
      (m, str) => str ? str : ' ');
  try { return { result: JSON.parse(rep), strategy: 'repair', repaired: true }; }
  catch(e) {}

  return { result: null, strategy: 'failed', repaired: false };
}

const { result: parsed, strategy: parseStrategy, repaired: wasRepaired } = extractJSON(rawText);
const parseError = parsed ? null : `Draft JSON extraction failed. Strategy: ${parseStrategy}. Finish: ${finishReason}. Length: ${rawText.length}`;
let d = parsed || {};

// ─────────────────────────────────────────────────────────────────────────
// 4. DRAFT TEXT EXTRACTION & VALIDATION
