// ─────────────────────────────────────────────────────────────────────────
// 5. FALLBACK DRAFT GENERATION (when AI fails or returns empty)
// ─────────────────────────────────────────────────────────────────────────
function buildFallback() {
  const priority = item.priorityClass || 'MEDIUM';
  const intent   = item.intent        || 'OTHER';
