}

const draftText = hasDraft ? d.draft_reply.trim() : buildFallback();
const usedFallback = !hasDraft;

// ─────────────────────────────────────────────────────────────────────────
// 6. PLACEHOLDER ANALYSIS
// ─────────────────────────────────────────────────────────────────────────
function extractPlaceholders(text) {
  const needsInput = [...text.matchAll(/\[NEEDS INPUT:\s*([^\]]+)\]/gi)]
    .map(m => ({ type: 'NEEDS_INPUT', description: m[1].trim(), raw: m[0] }));
  const verify     = [...text.matchAll(/\[VERIFY:\s*([^\]]+)\]/gi)]
    .map(m => ({ type: 'VERIFY',      description: m[1].trim(), raw: m[0] }));
  const warnings   = [...text.matchAll(/\[WARNING:\s*([^\]]+)\]/gi)]
    .map(m => ({ type: 'WARNING',     description: m[1].trim(), raw: m[0] }));
  return { needsInput, verify, warnings, all: [...needsInput, ...verify, ...warnings] };
}

const placeholders = extractPlaceholders(draftText);
const ni  = placeholders.needsInput.length;
const vc  = placeholders.verify.length;
const wc  = placeholders.warnings.length;
const hp  = ni + vc + wc > 0;

// Flagged items — merge AI-provided + extracted
const flaggedItemsFromAI  = Array.isArray(d.flagged_items) ? d.flagged_items : [];
const flaggedItemsExtracted = placeholders.all.map(p => `[${p.type}] ${p.description}`);
// Deduplicate
const allFlaggedSet = new Set([...flaggedItemsFromAI, ...flaggedItemsExtracted]);
const flaggedItems  = [...allFlaggedSet].filter(Boolean);

// ─────────────────────────────────────────────────────────────────────────
// 7. STRUCTURAL ANALYSIS
//    Checks draft has all required sections
// ─────────────────────────────────────────────────────────────────────────
function analyzeStructure(text) {
  const lines       = text.split('\n').map(l => l.trim()).filter(Boolean);
  const firstLine   = lines[0] || '';
  const lastLine    = lines[lines.length - 1] || '';
  const secondLast  = lines[lines.length - 2] || '';

  const hasSalutation = /^(dear|hi|hello|good\s+(morning|afternoon|evening))/i.test(firstLine);
  const hasClosing    = /^(regards?|best|sincerely|yours|kind regards?|faithfully|cheers?|thanks?)/i.test(secondLast) ||
                        /^(regards?|best|sincerely|yours|kind regards?|faithfully|cheers?|thanks?)/i.test(lastLine);
  const hasSignature  = lastLine.includes(userName) ||
                        lastLine.toLowerCase().includes(orgName.toLowerCase()) ||
                        lastLine.includes(userTitle) ||
                        /\|/.test(lastLine);
  const hasBody       = lines.length >= 3;
  const wordCount     = text.split(/\s+/).filter(Boolean).length;
  const lineCount     = lines.length;
  const paraCount     = text.split(/\n{2,}/).filter(p => p.trim().length > 0).length;

  return {
    hasSalutation,
    hasClosing,
    hasSignature,
    hasBody,
    wordCount,
    lineCount,
    paraCount,
    firstLine,
    lastLine,
    structureComplete: hasSalutation && hasClosing && hasBody,
  };
}

const structure = analyzeStructure(draftText);

// ─────────────────────────────────────────────────────────────────────────
// 8. ANTI-PATTERN DETECTION
//    Catches prohibited phrases from the reply prompt anti-patterns library
// ─────────────────────────────────────────────────────────────────────────
const ANTI_PATTERNS = [
  { pattern: /i hope this email finds you well/i,          label: 'Generic opener: "I hope this email finds you well"' },
  { pattern: /as per my previous email/i,                  label: 'Passive-aggressive: "as per my previous email"' },
  { pattern: /please do not hesitate to (contact|reach)/i, label: 'Cliché closer: "please do not hesitate to contact"' },
  { pattern: /going forward,?\s+we\s+will/i,               label: 'Corporate filler: "going forward"' },
  { pattern: /at this point in time/i,                     label: 'Verbose: "at this point in time" (say "now")' },
  { pattern: /i wanted to reach out/i,                     label: 'Filler: "I wanted to reach out"' },
  { pattern: /our team is (working on|looking into) it/i,  label: 'Vague: "our team is working on it" without specifics' },
  { pattern: /hopefully/i,                                  label: 'Projects doubt: "hopefully" — use "I will" or "we will"' },
  { pattern: /i think maybe/i,                             label: 'Uncertain: "I think maybe"' },
  { pattern: /basically/i,                                  label: 'Informal: "basically"' },
  { pattern: /we are committed to (excellence|quality|customer satisfaction)/i, label: 'Empty pledge: "committed to excellence/quality"' },
  { pattern: /sorry to bother you/i,                       label: 'Self-undermining: "sorry to bother you"' },
  { pattern: /just checking in/i,                          label: 'Weak opener: "just checking in"' },
  { pattern: /\bfyi\b/i,                                   label: 'Informal abbreviation: "FYI" in a formal reply' },
];

const antiPatternHits = ANTI_PATTERNS
  .filter(ap => ap.pattern.test(draftText))
  .map(ap => ap.label);

// ─────────────────────────────────────────────────────────────────────────
// 9. LEGAL & REGULATORY COMPLIANCE CHECK
// ─────────────────────────────────────────────────────────────────────────
const legalFlag     = item.legalFlag     || false;
const regFlag       = item.regulatoryFlag|| false;
const finFlag       = item.financialFlag || false;
const secFlag       = item.securityFlag  || false;

const complianceIssues = [];

// Legal flag — draft should have legal review warning
if (legalFlag && !draftText.includes('[WARNING:')) {
  complianceIssues.push('Legal flag set but draft has no [WARNING: LEGAL REVIEW REQUIRED] block — add before sending');
}

// Legal flag — draft should NOT have substantive positions
const substantivePatterns = [
  /we deny/i, /we admit/i, /we accept (liability|responsibility)/i,
  /this claim is (without merit|unfounded)/i, /we are not liable/i,
  /we will (defend|contest|challenge)/i,
];
if (legalFlag && substantivePatterns.some(p => p.test(draftText))) {
  complianceIssues.push('CRITICAL: Draft appears to contain a substantive legal position — must be removed before any legal send');
}

// Regulatory flag — draft should have regulatory review warning
if (regFlag && !draftText.includes('[WARNING:')) {
  complianceIssues.push('Regulatory flag set but draft has no [WARNING: REGULATORY COUNSEL REVIEW] block');
}

// Financial flag — check for unverified monetary commitments
if (finFlag && item.monetaryAmounts && item.monetaryAmounts.length > 0) {
  const hasVerifyForAmounts = item.monetaryAmounts.some(amt => {
    const escaped = amt.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    return new RegExp(escaped, 'i').test(draftText) &&
           !draftText.includes('[VERIFY:');
  });
  if (hasVerifyForAmounts) {
    complianceIssues.push(`Financial amounts present (${item.monetaryAmounts.join(', ')}) but no [VERIFY:] tags found — add verification placeholders`);
  }
}

// Security flag — draft should route, not describe
if (secFlag) {
  const scopePatterns = [/\d+\s*(accounts?|users?|records?)\s*(were|are|have been)\s*(compromised|affected|exposed)/i];
  if (scopePatterns.some(p => p.test(draftText))) {
    complianceIssues.push('Security flag: draft appears to confirm scope of incident — remove specifics, route to CISO');
  }
}

const requiresLegalReview = legalFlag ||
  safeBool(d.requires_legal_review) ||
  complianceIssues.some(i => i.toLowerCase().includes('legal'));

const requiresTechReview = secFlag ||
  safeBool(d.requires_technical_review) ||
  (item.intent === 'AUDIT' || item.intent === 'INSPECTION');

function safeBool(v, def = false) {
  if (typeof v === 'boolean') return v;
  if (v === 'true' || v === 1) return true;
  if (v === 'false'|| v === 0) return false;
  return def;
}

// ─────────────────────────────────────────────────────────────────────────
// 10. COMMITMENT EXTRACTION
//     Finds specific promises: "I will X by Y", "We will deliver Z on W"
// ─────────────────────────────────────────────────────────────────────────
function extractCommitments(text) {
  const commitments = [];

  // Pattern: "I will / We will + action + by/on/before + time"
  const willPattern = /(?:I|we) will ([^.!?\n]{5,80})(?:\s+by\s+|\s+on\s+|\s+before\s+|\s+no later than\s+)([^.!?\n]{3,50})/gi;
  for (const m of text.matchAll(willPattern)) {
    commitments.push({ type: 'WILL_DO', action: m[1].trim(), by: m[2].trim() });
  }

  // Pattern: "I will respond / get back / update + by/before + time"
  const responsePattern = /(?:I|we) will (?:respond|get back|update|follow up|send|provide|share|call|contact)[^.!?\n]{0,50}(?:by|before|no later than|within)\s+([^.!?\n]{3,50})/gi;
  for (const m of text.matchAll(responsePattern)) {
    if (!commitments.find(c => c.by === m[1].trim())) {
      commitments.push({ type: 'FOLLOW_UP', action: 'Response/update', by: m[1].trim() });
    }
  }

  // Pattern: "expect X by Y", "you will receive X by Y"
  const expectPattern = /(?:expect|you will receive|you will hear)[^.!?\n]{3,60}(?:by|before|on)\s+([^.!?\n]{3,50})/gi;
  for (const m of text.matchAll(expectPattern)) {
    commitments.push({ type: 'EXPECTATION', action: 'Response/delivery', by: m[1].trim() });
  }

  // From AI field if provided
  if (Array.isArray(d.key_commitments)) {
    d.key_commitments.forEach(c => {
      if (typeof c === 'string') commitments.push({ type: 'AI_EXTRACTED', action: c, by: null });
      else if (c && c.action)   commitments.push({ type: 'AI_EXTRACTED', ...c });
    });
  }

  // Deduplicate
  const seen = new Set();
  return commitments.filter(c => {
    const k = c.type + ':' + c.action + ':' + (c.by || '');
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  });
}

const commitments = extractCommitments(draftText);

// ─────────────────────────────────────────────────────────────────────────
// 11. TONE & REGISTER VALIDATION
// ─────────────────────────────────────────────────────────────────────────
const toneUsed  = d.tone_used || 'unknown';
const register  = d.register  || 'EXTERNAL';
const aiQuality = d.quality_rating || 'NEEDS_REVIEW';

// Validate AI quality rating against actual placeholder count
let qualityRating = aiQuality;
if (ni > 3 && qualityRating === 'CONFIDENT') qualityRating = 'PARTIAL';
if (ni > 0 && wc > 0 && qualityRating !== 'NEEDS_REVIEW') qualityRating = 'NEEDS_REVIEW';
if (usedFallback) qualityRating = 'NEEDS_REVIEW';
if (complianceIssues.some(i => i.startsWith('CRITICAL'))) qualityRating = 'NEEDS_REVIEW';

// ─────────────────────────────────────────────────────────────────────────
// 12. 8-SIGNAL QUALITY SCORE (0–100)
// ─────────────────────────────────────────────────────────────────────────
function computeQualityScore() {
  let score = 70; // neutral baseline

  // Structure completeness (+/-)
  if (structure.hasSalutation)   score += 8;
  if (structure.hasClosing)      score += 8;
  if (structure.hasSignature)    score += 6;
  if (!structure.hasBody)        score -= 20;

  // Placeholder burden
  score -= ni * 8;   // each NEEDS INPUT costs 8 points
  score -= vc * 3;   // each VERIFY costs 3 points
  score -= wc * 5;   // each WARNING costs 5 points

  // Compliance issues
  score -= complianceIssues.length * 15;

  // Anti-pattern hits
  score -= antiPatternHits.length * 5;

  // Length appropriateness
  const priority = item.priorityClass || 'MEDIUM';
  const IDEAL_WORDS = { CRITICAL: [80, 200], HIGH: [100, 250], MEDIUM: [80, 250], LOW: [40, 150], NOISE: [10, 80] };
  const [minW, maxW] = IDEAL_WORDS[priority] || [60, 250];
  if (structure.wordCount < minW) score -= 10;
  if (structure.wordCount > maxW * 1.5) score -= 8;

  // AI confidence contribution
  const aiConf = parseFloat(d.confidence_score) || 0.5;
  score += Math.round((aiConf - 0.5) * 20); // ±10 points

  // Fallback penalty
  if (usedFallback) score -= 30;

  // Truncated response penalty
  if (wasCut) score -= 15;

  // Repair penalty
  if (wasRepaired) score -= 5;

  return Math.min(100, Math.max(0, score));
}

const qualityScore = computeQualityScore();

// ─────────────────────────────────────────────────────────────────────────
// 13. DRAFT READINESS ROUTING
// ─────────────────────────────────────────────────────────────────────────
// READY         — can approve with a glance; no blocking issues
// NEEDS_INPUT   — has [NEEDS INPUT] tags; user must fill before sending
// LEGAL_REVIEW  — legal review warning present; cannot send without counsel
// NEEDS_REWORK  — critical compliance issue; must be manually corrected
const draftStatus =
    complianceIssues.some(i => i.startsWith('CRITICAL')) ? 'NEEDS_REWORK'
  : requiresLegalReview || wc > 0                        ? 'LEGAL_REVIEW'
  : ni > 0                                               ? 'NEEDS_INPUT'
  : qualityScore >= 60 && !usedFallback                  ? 'READY'
  :                                                        'NEEDS_INPUT';

// ─────────────────────────────────────────────────────────────────────────
// 14. TOKEN & COST ACCOUNTING
// ─────────────────────────────────────────────────────────────────────────
const H          = k => httpHeaders[k] || httpHeaders[k.toLowerCase()] || null;
const usage      = responseBody?.usage || {};
const inTokens   = usage.prompt_tokens     || usage.input_tokens     || item._totalInputTokensEst || 0;
const outTokens  = usage.completion_tokens || usage.output_tokens    || 0;
const cacheRead  = usage.cache_read_input_tokens                     || 0;
const cacheWrite = usage.cache_creation_input_tokens                 || 0;

const MODEL_RATES = {
  'anthropic/claude-sonnet-4-5': { inp: 3.00,  out: 15.00, cr: 0.30,   cw: 3.75  },
  'openai/gpt-4o':               { inp: 2.50,  out: 10.00, cr: 1.25,   cw: 0     },
  'openai/gpt-4o-mini':          { inp: 0.15,  out: 0.60,  cr: 0.075,  cw: 0     },
  'google/gemini-pro-1.5':       { inp: 1.25,  out: 5.00,  cr: 0.3125, cw: 0     },
  'google/gemini-flash-1.5':     { inp: 0.075, out: 0.30,  cr: 0.01875,cw: 0     },
  'meta-llama/llama-3.3-70b-instruct': { inp: 0.20, out: 0.20, cr: 0,  cw: 0     },
};

const modelId  = responseBody?.model || item._selectedModel || 'unknown';
const rates    = MODEL_RATES[modelId] || { inp: 0, out: 0, cr: 0, cw: 0 };
const costUSD  = (inTokens   / 1_000_000 * rates.inp)
               + (outTokens  / 1_000_000 * rates.out)
               + (cacheRead  / 1_000_000 * rates.cr)
               + (cacheWrite / 1_000_000 * rates.cw);

// Rate limit state
const rlRemaining = parseInt(H('x-ratelimit-remaining-requests') || H('x-ratelimit-remaining') || '999');
const rlReset     = H('x-ratelimit-reset-requests') || null;

// ─────────────────────────────────────────────────────────────────────────
// 15. QUALITY FLAGS ARRAY
// ─────────────────────────────────────────────────────────────────────────
const qualityFlags = [];
if (parseError)                      qualityFlags.push('PARSE_FAILED');
if (wasRepaired)                     qualityFlags.push('JSON_REPAIRED');
if (usedFallback)                    qualityFlags.push('FALLBACK_DRAFT_USED');
if (wasCut)                          qualityFlags.push('RESPONSE_TRUNCATED');
if (antiPatternHits.length > 0)      qualityFlags.push('ANTI_PATTERNS_DETECTED');
if (complianceIssues.length > 0)     qualityFlags.push('COMPLIANCE_ISSUES');
if (complianceIssues.some(i => i.startsWith('CRITICAL'))) qualityFlags.push('CRITICAL_COMPLIANCE_ISSUE');
if (!structure.hasSalutation)        qualityFlags.push('MISSING_SALUTATION');
if (!structure.hasClosing)           qualityFlags.push('MISSING_CLOSING');
if (!structure.hasSignature)         qualityFlags.push('MISSING_SIGNATURE');
if (ni > 0)                          qualityFlags.push(`NEEDS_INPUT_x${ni}`);
if (vc > 0)                          qualityFlags.push(`VERIFY_x${vc}`);
if (wc > 0)                          qualityFlags.push(`WARNINGS_x${wc}`);
if (requiresLegalReview)             qualityFlags.push('LEGAL_REVIEW_REQUIRED');
if (requiresTechReview)              qualityFlags.push('TECH_REVIEW_REQUIRED');

const overallQuality =
    qualityFlags.includes('CRITICAL_COMPLIANCE_ISSUE') ? 'BLOCKED'
  : qualityFlags.includes('PARSE_FAILED')              ? 'FAILED'
  : qualityFlags.includes('FALLBACK_DRAFT_USED')       ? 'FALLBACK'
  : qualityFlags.includes('COMPLIANCE_ISSUES')         ? 'REVIEW_REQUIRED'
  : qualityFlags.length === 0                          ? 'CLEAN'
  : qualityScore >= 70                                 ? 'GOOD'
  : qualityScore >= 50                                 ? 'ACCEPTABLE'
  :                                                      'POOR';

// ─────────────────────────────────────────────────────────────────────────
// 16. FINAL OUTPUT
// ─────────────────────────────────────────────────────────────────────────
return [{ json: {
  // ── Original classification fields pass-through ──
  messageId:                  item.messageId,
  threadId:                   item.threadId,
  senderName:                 item.senderName,
  senderEmail:                item.senderEmail,
  senderDomain:               item.senderDomain,
  subject:                    item.subject,
  bodyText:                   item.bodyText,
  receivedAt:                 item.receivedAt,
  source:                     item.source,
  hasAttachment:              item.hasAttachment,
  attachments:                item.attachments,
  attachmentNames:            item.attachmentNames,
  attachmentTypes:            item.attachmentTypes,
  isVIP:                      item.isVIP,
  isInternal:                 item.isInternal,
  isDirectTO:                 item.isDirectTO,
  isCCOnly:                   item.isCCOnly,
  priorityClass:              item.priorityClass,
  urgencyScore:               item.urgencyScore,
  confidenceScore:            item.confidenceScore,
  slaBucket:                  item.slaBucket,
  slaDeadline:                item.slaDeadline,
  slaBreach:                  item.slaBreach,
  intent:                     item.intent,
  sentiment:                  item.sentiment,
  domainCategory:             item.domainCategory,
  domainSubcategory:          item.domainSubcategory,
  senderTier:                 item.senderTier,
  legalFlag:                  item.legalFlag,
  regulatoryFlag:             item.regulatoryFlag,
  financialFlag:              item.financialFlag,
  securityFlag:               item.securityFlag,
  hrFlag:                     item.hrFlag,
  escalationRecommended:      item.escalationRecommended,
  escalateTo:                 item.escalateTo,
  privilegeFlag:              item.privilegeFlag,
  preservationRequired:       item.preservationRequired,
  boardNotificationRequired:  item.boardNotificationRequired,
  actionItems:                item.actionItems,
  keyDeadlines:               item.keyDeadlines,
  keyStakeholders:            item.keyStakeholders,
  monetaryAmounts:            item.monetaryAmounts,
  referenceNumbers:           item.referenceNumbers,
  emailSummary:               item.emailSummary,
  classificationReason:       item.classificationReason,
  keyQuote:                   item.keyQuote,
  gmailLabels:                item.gmailLabels,
  preliminaryScore:           item.preliminaryScore,
  scoreLog:                   item.scoreLog,
  shouldDraft:                item.shouldDraft,
  apiModel:                   item.apiModel,
  apiRoutingTier:             item.apiRoutingTier,
  apiInputTokens:             item.apiInputTokens,
  apiOutputTokens:            item.apiOutputTokens,
  apiCostUSD:                 item.apiCostUSD,
  language:                   item.language,
  industry:                   item.industry,
  orgName:                    item.orgName,
  replySystemPrompt:          item.replySystemPrompt,
  replyUserPrompt:            item.replyUserPrompt,

  // ── Draft content ──
  draftReply:                 draftText,
  draftReplyOriginal:         hasDraft ? d.draft_reply : null, // raw before any processing
  usedFallback,

  // ── Quality ──
  draftQualityRating:         qualityRating,
  draftQualityScore:          qualityScore,
  draftConfidence:            Math.min(1, Math.max(0, parseFloat(d.confidence_score) || 0.5)),
  overallQuality,
  qualityFlags,

  // ── Placeholders ──
  draftHasPlaceholders:       hp,
  draftNeedsInputCount:       ni,
  draftVerifyCount:           vc,
  draftWarningCount:          wc,
  draftNeedsInputItems:       placeholders.needsInput.map(p => p.description),
  draftVerifyItems:           placeholders.verify.map(p => p.description),
  draftWarnings:              placeholders.warnings.map(p => p.description),
  draftFlaggedItems:          flaggedItems,

  // ── Compliance ──
  draftRequiresLegal:         requiresLegalReview,
  draftRequiresTech:          requiresTechReview,
  complianceIssues,
  draftStatus,

  // ── Structure ──
  draftWordCount:             structure.wordCount,
  draftLineCount:             structure.lineCount,
  draftParaCount:             structure.paraCount,
  draftHasSalutation:         structure.hasSalutation,
  draftHasClosing:            structure.hasClosing,
  draftHasSignature:          structure.hasSignature,
  draftStructureComplete:     structure.structureComplete,

  // ── Anti-patterns ──
  draftAntiPatternCount:      antiPatternHits.length,
  draftAntiPatterns:          antiPatternHits,

  // ── Commitments ──
  draftCommitments:           commitments,
  keyCommitments:             d.key_commitments || commitments.map(c => `${c.action}${c.by ? ' by ' + c.by : ''}`),

  // ── Tone / register ──
  draftToneUsed:              toneUsed,
  draftRegister:              register,
  draftReplySummary:          d.reply_summary  || `${qualityRating} draft for ${item.intent || 'unknown'} intent`,
  draftEscalationAddressed:   safeBool(d.escalation_addressed),
  draftAiWarnings:            Array.isArray(d.warnings) ? d.warnings : [],

  // ── Parse metadata ──
  draftParseError:            parseError,
  draftParseStrategy:         parseStrategy,
  draftWasRepaired:           wasRepaired,
  draftWasCut:                wasCut,
  draftFinishReason:          finishReason,

  // ── API provenance ──
  draftApiModel:              modelId,
  draftApiInputTokens:        inTokens,
  draftApiOutputTokens:       outTokens,
  draftApiCacheReadTokens:    cacheRead,
  draftApiCacheWriteTokens:   cacheWrite,
  draftApiCostUSD:            Math.round(costUSD * 1_000_000) / 1_000_000,
  draftApiHttpStatus:         httpStatus,
  draftApiRlRemaining:        rlRemaining,
  draftApiRlReset:            rlReset,
  draftApiRequestId:          item._requestId,

  // ── Timestamps ──
  draftCreatedAt:             new Date().toISOString(),
  processingStatus:           'DRAFT_READY',
  pipelineVersion:            '4.0',
}}];

// ═══════════════════════════════════════════════════════════════════════════
// SLA BREACH PROCESSOR — v4.0 ADVANCED
// ─────────────────────────────────────────────────────────────────────────
// Runs every 15 minutes via Schedule Trigger.
// Receives rows from PostgreSQL Query Near Breach Emails.
//
// Pipeline:
//   1.  Input normalization — handles single row or array
//   2.  Per-email SLA metrics computation
//   3.  Alert level classification (WARNING → BREACH → CRITICAL_OVERDUE)
//   4.  Escalation decision with business hours awareness
//   5.  Slack message building (real newlines — no join issue)
//   6.  Gmail alert body building
//   7.  PostgreSQL upsert payload construction
//   8.  Per-email routing decision (alert / skip / deduplicate)
//   9.  Batch summary for analytics
//  10.  Structured output — one item per actionable breach
// ═══════════════════════════════════════════════════════════════════════════

// ─────────────────────────────────────────────────────────────────────────
// HARDCODED CONFIG — edit these values
// ─────────────────────────────────────────────────────────────────────────
const CFG = {
  userName:          'Akshat Jain',
  userEmail:         'jainakshatsunil@gmail.com',
  orgName:           'PharmaOS',
  notificationEmail: 'jainakshatsunil@gmail.com',
  escalationEmail:   'jainakshatsunil@gmail.com',
  slackChannel:      '#email-alerts',
  dashboardUrl:      'http://localhost:3001',

  // Warning = SLA is 80% elapsed but not yet breached
  warningThresholdPct: 80,

  // Critical overdue = breached by more than this many hours
  criticalOverdueHours: 4,

  // Business hours (local time) — escalations only during these hours
  businessHoursStart: 8,   // 8 AM
  businessHoursEnd:   20,  // 8 PM

  // De-duplicate: skip re-alerting if same (messageId + alert_level)
  // was already logged in eih_notification_log within this many minutes
  dedupeWindowMinutes: 60,
};

// ─────────────────────────────────────────────────────────────────────────
// 1. INPUT NORMALIZATION
//    PostgreSQL node returns items — each item.json is one row
// ─────────────────────────────────────────────────────────────────────────
const allItems = $input.all();

if (!allItems || allItems.length === 0) {
  return [{ json: {
    batchProcessed:    0,
    batchWarning:      0,
    batchBreach:       0,
    batchCritical:     0,
    batchSkipped:      0,
    processedAt:       new Date().toISOString(),
    hasAlerts:         false,
    alerts:            [],
    summary:           'No emails near SLA — all clear',
  }}];
}

const rows = allItems.map(i => i.json);

// ─────────────────────────────────────────────────────────────────────────
// 2. UTILITY FUNCTIONS
// ─────────────────────────────────────────────────────────────────────────
function now() { return new Date(); }

function diffHours(dateA, dateB) {
  return (new Date(dateA) - new Date(dateB)) / 3_600_000;
}

function diffMinutes(dateA, dateB) {
  return (new Date(dateA) - new Date(dateB)) / 60_000;
}

function isBusinessHours() {
  const h = now().getHours();
  return h >= CFG.businessHoursStart && h < CFG.businessHoursEnd;
}

function fmtDate(iso) {
  if (!iso) return 'N/A';
  return new Date(iso).toLocaleString('en-IN', {
    day: '2-digit', month: 'short', year: 'numeric',
    hour: '2-digit', minute: '2-digit', hour12: true,
  });
}

function fmtHours(h) {
  if (h == null) return 'N/A';
  const abs = Math.abs(h);
  if (abs < 1)  return Math.round(abs * 60) + ' min';
  if (abs < 24) return abs.toFixed(1) + 'h';
  return (abs / 24).toFixed(1) + 'd';
}

function pctBar(pct, width = 20) {
  const filled = Math.round(Math.min(100, Math.max(0, pct)) / 100 * width);
  return '█'.repeat(filled) + '░'.repeat(width - filled);
}

// ─────────────────────────────────────────────────────────────────────────
// 3. SLA METRICS PER EMAIL
// ─────────────────────────────────────────────────────────────────────────
function computeSLAMetrics(row) {
  const receivedAt  = new Date(row.received_at  || row.receivedAt);
  const slaDeadline = new Date(row.sla_deadline || row.slaDeadline);
  const nowTs       = now();

  const totalWindowHours   = diffHours(slaDeadline, receivedAt);
  const elapsedHours       = diffHours(nowTs, receivedAt);
  const hoursRemaining     = diffHours(slaDeadline, nowTs);   // negative = breached
  const hoursOverdue       = hoursRemaining < 0 ? Math.abs(hoursRemaining) : 0;
  const pctElapsed         = totalWindowHours > 0
    ? Math.min(100, Math.round(elapsedHours / totalWindowHours * 100))
    : 100;

  const isBreach           = hoursRemaining < 0;
  const isWarning          = !isBreach && pctElapsed >= CFG.warningThresholdPct;
  const isCriticalOverdue  = isBreach && hoursOverdue >= CFG.criticalOverdueHours;

  return {
    receivedAt, slaDeadline, nowTs,
    totalWindowHours: Math.round(totalWindowHours * 10) / 10,
    elapsedHours:     Math.round(elapsedHours     * 10) / 10,
    hoursRemaining:   Math.round(hoursRemaining   * 10) / 10,
    hoursOverdue:     Math.round(hoursOverdue      * 10) / 10,
    pctElapsed,
    isBreach,
    isWarning,
    isCriticalOverdue,
  };
}

// ─────────────────────────────────────────────────────────────────────────
// 4. ALERT LEVEL CLASSIFICATION
// ─────────────────────────────────────────────────────────────────────────
function classifyAlertLevel(metrics) {
  if (metrics.isCriticalOverdue) return 'CRITICAL_OVERDUE';
  if (metrics.isBreach)          return 'BREACH_RECENT';
  if (metrics.isWarning)         return 'WARNING_IMMINENT';
  return null; // no alert needed
}

// ─────────────────────────────────────────────────────────────────────────
// 5. ESCALATION DECISION
// ─────────────────────────────────────────────────────────────────────────
function shouldEscalate(row, metrics, alertLevel) {
  if (alertLevel !== 'CRITICAL_OVERDUE' && alertLevel !== 'BREACH_RECENT') return false;
  // Only escalate during business hours unless CRITICAL_OVERDUE
  if (!isBusinessHours() && alertLevel !== 'CRITICAL_OVERDUE') return false;
  // Only escalate CRITICAL + HIGH priority emails
  const priority = row.priority_class || row.priorityClass || '';
  if (!['CRITICAL', 'HIGH'].includes(priority)) return false;
  return true;
}

// ─────────────────────────────────────────────────────────────────────────
// 6. ALERT LEVEL DISPLAY METADATA
// ─────────────────────────────────────────────────────────────────────────
const ALERT_META = {
  WARNING_IMMINENT: {
    emoji:    ':warning:',
    label:    'SLA Warning',
    color:    '#BA7517',
    urgency:  'medium',
  },
  BREACH_RECENT: {
    emoji:    ':rotating_light:',
    label:    'SLA Breach',
    color:    '#E24B4A',
    urgency:  'high',
  },
  CRITICAL_OVERDUE: {
    emoji:    ':sos:',
    label:    'SLA Critical Overdue',
    color:    '#A32D2D',
    urgency:  'critical',
  },
};

// ─────────────────────────────────────────────────────────────────────────
// 7. SLACK MESSAGE BUILDER  (real \n — no join issue)
// ─────────────────────────────────────────────────────────────────────────
function buildSlackMessage(row, metrics, alertLevel, needsEscalation) {
  const am       = ALERT_META[alertLevel];
  const priority = row.priority_class || row.priorityClass || '';
  const subject  = row.subject || '(No Subject)';
  const sender   = (row.sender_name || row.senderName || '') + ' — ' + (row.sender_email || row.senderEmail || '');
  const domain   = row.sender_domain || row.senderDomain || '';
  const bar      = pctBar(metrics.pctElapsed);

  let msg = am.emoji + ' *' + am.label + ' — ' + priority + ' Email*\n\n';
  msg += '*' + subject + '*\n';
  msg += 'From: ' + sender + '  |  ' + domain + '\n\n';

  // SLA status bar
  msg += '*SLA progress:* `' + bar + '` ' + metrics.pctElapsed + '%\n';

  if (metrics.isBreach) {
    msg += '*Overdue by:*  :fire: ' + fmtHours(metrics.hoursOverdue) + '\n';
    msg += '*Deadline was:*  ' + fmtDate(row.sla_deadline || row.slaDeadline) + '\n';
  } else {
    msg += '*Time remaining:*  ' + fmtHours(metrics.hoursRemaining) + '\n';
    msg += '*Deadline:*  ' + fmtDate(row.sla_deadline || row.slaDeadline) + '\n';
  }

  msg += '*SLA bucket:*  ' + (row.sla_bucket || row.slaBucket || '') + '\n';
  msg += '*Received:*  ' + fmtDate(row.received_at || row.receivedAt) + '\n\n';

  // Risk flags if present
  const flags = [
    row.legal_flag       && ':scales: Legal',
    row.regulatory_flag  && ':clipboard: Regulatory',
    row.financial_flag   && ':moneybag: Financial',
    row.security_flag    && ':lock: Security',
  ].filter(Boolean);
  if (flags.length > 0) {
    msg += '*Flags:*  ' + flags.join('   ') + '\n\n';
  }

  if (needsEscalation) {
    msg += ':warning: *Escalation triggered* — ' +
      (row.escalate_to || row.escalateTo || 'Senior Leadership') + '\n\n';
  }

  msg += '_Open dashboard to take action: ' + CFG.dashboardUrl + '_\n';
  msg += '_' + CFG.orgName + '  ·  ' + now().toLocaleString() + '_';

  return msg;
}

// ─────────────────────────────────────────────────────────────────────────
// 8. GMAIL ALERT BODY BUILDER
// ─────────────────────────────────────────────────────────────────────────
function buildGmailSubject(row, metrics, alertLevel) {
  const am       = ALERT_META[alertLevel];
  const priority = row.priority_class || row.priorityClass || '';
  const overdue  = metrics.isBreach ? ' [OVERDUE ' + fmtHours(metrics.hoursOverdue) + ']' : '';
  return '[EIH] ' + am.label + ' — ' + priority + overdue + ': ' + (row.subject || '');
}

function buildGmailBody(row, metrics, alertLevel, needsEscalation) {
  const am = ALERT_META[alertLevel];
  let body = am.label.toUpperCase() + ' — EMAIL INTELLIGENCE HUB ALERT\n\n';
  body += 'EMAIL: ' + (row.subject || '') + '\n';
  body += 'FROM: ' + (row.sender_name || row.senderName || '') +
          ' <' + (row.sender_email || row.senderEmail || '') + '>\n';
  body += 'PRIORITY: ' + (row.priority_class || row.priorityClass || '') + '\n';
  body += 'SLA BUCKET: ' + (row.sla_bucket || row.slaBucket || '') + '\n\n';

  if (metrics.isBreach) {
    body += 'OVERDUE BY: ' + fmtHours(metrics.hoursOverdue) + '\n';
    body += 'DEADLINE WAS: ' + fmtDate(row.sla_deadline || row.slaDeadline) + '\n';
  } else {
    body += 'TIME REMAINING: ' + fmtHours(metrics.hoursRemaining) + '\n';
    body += 'DEADLINE: ' + fmtDate(row.sla_deadline || row.slaDeadline) + '\n';
  }

  body += 'SLA ELAPSED: ' + metrics.pctElapsed + '%\n\n';

  if (needsEscalation) {
    body += 'ESCALATION REQUIRED: ' +
      (row.escalate_to || row.escalateTo || 'Senior Leadership') + '\n\n';
  }

  body += 'ACTION REQUIRED: Open your email dashboard immediately.\n';
  body += CFG.dashboardUrl + '\n\n';
  body += '---\n';
  body += 'Email Intelligence Hub v4.0 | ' + CFG.orgName + '\n';
  body += 'Generated: ' + now().toISOString();

  return body;
}

// ─────────────────────────────────────────────────────────────────────────
// 9. POSTGRESQL UPSERT PAYLOAD
// ─────────────────────────────────────────────────────────────────────────
function buildDBPayload(row, metrics, alertLevel, needsEscalation) {
  return {
    message_id:       row.message_id     || row.messageId,
    subject:          row.subject,
    sender_email:     row.sender_email   || row.senderEmail,
    sender_name:      row.sender_name    || row.senderName,
    priority_class:   row.priority_class || row.priorityClass,
    sla_bucket:       row.sla_bucket     || row.slaBucket,
    sla_deadline:     row.sla_deadline   || row.slaDeadline,
    received_at:      row.received_at    || row.receivedAt,
    hours_overdue:    metrics.hoursOverdue,
    hours_left:       Math.max(0, metrics.hoursRemaining),
    pct_elapsed:      metrics.pctElapsed,
    alert_level:      alertLevel,
    alert_message:    ALERT_META[alertLevel].label + ' — ' + fmtHours(metrics.hoursOverdue || 0) + ' overdue',
    needs_escalation: needsEscalation,
    escalation_sent:  false,
    checked_at:       now().toISOString(),
  };
}

// ─────────────────────────────────────────────────────────────────────────
// 10. MAIN PROCESSING LOOP
// ─────────────────────────────────────────────────────────────────────────
const alerts   = [];
let countWarn  = 0;
let countBreach= 0;
let countCrit  = 0;
let countSkip  = 0;

for (const row of rows) {
  // Skip rows without SLA deadline
  if (!row.sla_deadline && !row.slaDeadline) { countSkip++; continue; }
  if (!row.received_at  && !row.receivedAt)  { countSkip++; continue; }

  const metrics    = computeSLAMetrics(row);
  const alertLevel = classifyAlertLevel(metrics);

  // No alert needed (email is on track, below warning threshold)
  if (!alertLevel) { countSkip++; continue; }

  const needsEscalation = shouldEscalate(row, metrics, alertLevel);

  // Count by level
  if (alertLevel === 'WARNING_IMMINENT')  countWarn++;
  if (alertLevel === 'BREACH_RECENT')     countBreach++;
  if (alertLevel === 'CRITICAL_OVERDUE')  countCrit++;

  const slackMsg    = buildSlackMessage(row, metrics, alertLevel, needsEscalation);
  const gmailSubj   = buildGmailSubject(row, metrics, alertLevel);
  const gmailBody   = buildGmailBody(row, metrics, alertLevel, needsEscalation);
  const dbPayload   = buildDBPayload(row, metrics, alertLevel, needsEscalation);

  alerts.push({
    // Row identity
    messageId:          row.message_id    || row.messageId,
    threadId:           row.thread_id     || row.threadId,
    subject:            row.subject,
    senderName:         row.sender_name   || row.senderName,
    senderEmail:        row.sender_email  || row.senderEmail,
    priorityClass:      row.priority_class|| row.priorityClass,
    slaBucket:          row.sla_bucket    || row.slaBucket,
    escalateTo:         row.escalate_to   || row.escalateTo,

    // Computed metrics
    slaDeadline:        (row.sla_deadline || row.slaDeadline),
    receivedAt:         (row.received_at  || row.receivedAt),
    hoursOverdue:       metrics.hoursOverdue,
    hoursRemaining:     metrics.hoursRemaining,
    pctElapsed:         metrics.pctElapsed,
    isBreach:           metrics.isBreach,
    isWarning:          metrics.isWarning,
    isCriticalOverdue:  metrics.isCriticalOverdue,

    // Alert classification
    alertLevel,
    needsEscalation,
    alertEmoji:         ALERT_META[alertLevel].emoji,
    alertLabel:         ALERT_META[alertLevel].label,
    alertColor:         ALERT_META[alertLevel].color,
    alertUrgency:       ALERT_META[alertLevel].urgency,

    // Notification payloads
    slackMessage:       slackMsg,
    slackChannel:       CFG.slackChannel,
    gmailSubject:       gmailSubj,
    gmailBody:          gmailBody,
    gmailTo:            CFG.notificationEmail,
    gmailEscalationTo:  needsEscalation ? CFG.escalationEmail : null,

    // DB upsert payload
    dbPayload,

    // Routing flags
    sendSlack:          true,
    sendGmail:          alertLevel === 'CRITICAL_OVERDUE' || alertLevel === 'BREACH_RECENT',
    sendEscalation:     needsEscalation,
    isBusinessHours:    isBusinessHours(),

    processedAt:        now().toISOString(),
  });
}

// ─────────────────────────────────────────────────────────────────────────
// 11. BATCH SUMMARY (first output item — useful for logging)
// ─────────────────────────────────────────────────────────────────────────
const summary = {
  batchProcessed:   rows.length,
  batchWarning:     countWarn,
  batchBreach:      countBreach,
  batchCritical:    countCrit,
  batchSkipped:     countSkip,
  batchAlerts:      alerts.length,
  hasAlerts:        alerts.length > 0,
  hasCritical:      countCrit > 0,
  processedAt:      now().toISOString(),
  isBusinessHours:  isBusinessHours(),
  alerts,
  summary: alerts.length === 0
    ? 'All SLAs on track — no alerts needed'
    : [
        countCrit   > 0 ? countCrit   + ' critical overdue' : null,
        countBreach > 0 ? countBreach + ' breached'         : null,
        countWarn   > 0 ? countWarn   + ' warning'          : null,
      ].filter(Boolean).join(', '),
};

// Return one item per alert (for downstream Split-in-batches / per-email routing)
// Plus a summary item at index 0
if (alerts.length === 0) {
  return [{ json: summary }];
}

return [
  { json: summary },
  ...alerts.map(a => ({ json: a })),
];

// ═══════════════════════════════════════════════════════════════════════════
// BUILD ANALYTICS REPORT — v4.0 ADVANCED
// ─────────────────────────────────────────────────────────────────────────
// Runs daily at 7 AM via Schedule Trigger.
// Receives 7-day stats from PostgreSQL Analytics Query node.
// Builds: HTML email digest + Slack summary + plain text + JSON snapshot
//
// Pipeline:
//   1.  Config (hardcoded — no env vars)
//   2.  Input normalization — handles single row or array of daily rows
//   3.  Aggregate computation across 7-day window
//   4.  Trend detection (improving / declining / stable)
//   5.  SLA compliance scoring
//   6.  AI performance metrics
//   7.  Cost & token analytics
//   8.  Top domain / sender analysis
//   9.  Anomaly detection (spikes, drops, unusual patterns)
//  10.  HTML email digest (full rich report)
//  11.  Slack summary message (real newlines)
//  12.  Plain text summary
//  13.  Structured JSON snapshot for PostgreSQL
//  14.  Recommendations engine
// ═══════════════════════════════════════════════════════════════════════════

// ─────────────────────────────────────────────────────────────────────────
// 1. HARDCODED CONFIG
// ─────────────────────────────────────────────────────────────────────────
const CFG = {
  userName:          'Akshat Jain',
  userEmail:         'jainakshatsunil@gmail.com',
  orgName:           'PharmaOS',
  reportEmail:       'jainakshatsunil@gmail.com',
  slackChannel:      '#email-reports',
  dashboardUrl:      'http://localhost:3001',
  timezone:          'Asia/Kolkata',
  currency:          'USD',
  reportWindowDays:  7,
  // Thresholds for anomaly detection
  slaComplianceTarget:     90,   // % target
  draftApprovalTarget:     70,   // % target
  aiConfidenceTarget:      80,   // % target
  maxDailyCriticalNormal:  10,   // above this = spike
  maxDailyEmailsNormal:    300,  // above this = unusual volume
};

// ─────────────────────────────────────────────────────────────────────────
// 2. UTILITIES
// ─────────────────────────────────────────────────────────────────────────
const now = new Date();

function fmt(n, decimals = 0) {
  if (n == null || isNaN(n)) return '—';
  return Number(n).toFixed(decimals).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
}

function pct(n, total) {
  if (!total || total === 0) return 0;
  return Math.round(n / total * 100);
}

function pctStr(n, total) {
  return pct(n, total) + '%';
}

function trend(current, previous) {
  if (previous == null || previous === 0) return { dir: 'STABLE', delta: 0, symbol: '→' };
  const delta = ((current - previous) / previous * 100);
  if (delta >  5) return { dir: 'UP',   delta: Math.round(delta), symbol: '↑' };
  if (delta < -5) return { dir: 'DOWN', delta: Math.round(Math.abs(delta)), symbol: '↓' };
  return { dir: 'STABLE', delta: 0, symbol: '→' };
}

function avg(arr) {
  if (!arr || arr.length === 0) return 0;
  return arr.reduce((s, v) => s + (Number(v) || 0), 0) / arr.length;
}

function sum(arr) {
  if (!arr || arr.length === 0) return 0;
  return arr.reduce((s, v) => s + (Number(v) || 0), 0);
}

function max(arr) {
  if (!arr || arr.length === 0) return 0;
  return Math.max(...arr.map(v => Number(v) || 0));
}

function fmtDate(d) {
  return new Date(d).toLocaleDateString('en-IN', {
    weekday: 'short', day: 'numeric', month: 'short',
  });
}

function barH(value, maxVal, width = 20) {
  const filled = maxVal > 0 ? Math.round(value / maxVal * width) : 0;
  return '█'.repeat(Math.min(filled, width)) + '░'.repeat(Math.max(0, width - filled));
}

// ─────────────────────────────────────────────────────────────────────────
// 3. INPUT NORMALIZATION
// ─────────────────────────────────────────────────────────────────────────
const allItems = $input.all();
const rows     = allItems.map(i => i.json).filter(r => r && r.date);

if (rows.length === 0) {
  return [{ json: {
    reportType:    'ANALYTICS_DIGEST',
    reportDate:    now.toISOString().substring(0, 10),
    hasData:       false,
    emailSubject:  '[EIH] Daily Analytics Report — No Data',
    emailBody:     '<p>No email data available for the report window.</p>',
    slackMessage:  ':bar_chart: *EIH Daily Report* — No data available for the last 7 days.',
    plainText:     'EIH Daily Report — No data available.',
    generatedAt:   now.toISOString(),
  }}];
}

// Sort by date ascending
rows.sort((a, b) => new Date(a.date) - new Date(b.date));
const today    = rows[rows.length - 1]; // most recent day
const yesterday= rows.length >= 2 ? rows[rows.length - 2] : null;

// ─────────────────────────────────────────────────────────────────────────
// 4. AGGREGATE COMPUTATION
// ─────────────────────────────────────────────────────────────────────────
const AGG = {
  // Volume
  totalEmails:        sum(rows.map(r => r.total_emails         || 0)),
  totalCritical:      sum(rows.map(r => r.critical_count       || 0)),
  totalHigh:          sum(rows.map(r => r.high_count           || 0)),
  totalMedium:        sum(rows.map(r => r.medium_count         || 0)),
  totalLow:           sum(rows.map(r => r.low_count            || 0)),
  totalNoise:         sum(rows.map(r => r.noise_count          || 0)),
  totalReplyRequired: sum(rows.map(r => r.reply_required_count || 0)),

  // Domain breakdown
  totalRegulatory:    sum(rows.map(r => r.regulatory_count     || 0)),
  totalLegal:         sum(rows.map(r => r.legal_count          || 0)),
  totalFinancial:     sum(rows.map(r => r.financial_count      || 0)),
  totalClient:        sum(rows.map(r => r.client_count         || 0)),
  totalInternal:      sum(rows.map(r => r.internal_count       || 0)),

  // Risk flags
  totalLegalFlag:     sum(rows.map(r => r.legal_flag_count     || 0)),
  totalRegulatoryFlag:sum(rows.map(r => r.regulatory_flag_count|| 0)),
  totalFinancialFlag: sum(rows.map(r => r.financial_flag_count || 0)),
  totalSecurityFlag:  sum(rows.map(r => r.security_flag_count  || 0)),
  totalEscalations:   sum(rows.map(r => r.escalation_count     || 0)),

  // SLA
  totalSLABreaches:   sum(rows.map(r => r.sla_breach_count     || 0)),

  // Drafts
  totalDraftsGenerated:sum(rows.map(r => r.draft_generated_count|| 0)),
  totalDraftsApproved: sum(rows.map(r => r.draft_approved_count || 0)),
  totalDraftsRejected: sum(rows.map(r => r.draft_rejected_count || 0)),

  // AI performance
  avgConfidence:       avg(rows.map(r => r.avg_confidence      || 0)),
  totalLowConfidence:  sum(rows.map(r => r.low_confidence_count || 0)),
  totalErrors:         sum(rows.map(r => r.error_count         || 0)),

  // Today vs yesterday
  todayEmails:        Number(today.total_emails   || 0),
  todayCritical:      Number(today.critical_count || 0),
  todayDrafts:        Number(today.draft_generated_count || 0),
  yesterdayEmails:    yesterday ? Number(yesterday.total_emails   || 0) : null,
  yesterdayCritical:  yesterday ? Number(yesterday.critical_count || 0) : null,
};

// Daily averages
const days = rows.length;
AGG.avgDailyEmails    = Math.round(AGG.totalEmails / days);
AGG.avgDailyCritical  = Math.round(AGG.totalCritical / days);
AGG.peakDailyEmails   = max(rows.map(r => r.total_emails || 0));
AGG.peakDailyCritical = max(rows.map(r => r.critical_count || 0));

// Derived rates
AGG.noiseFilterRate   = pct(AGG.totalNoise, AGG.totalEmails);
AGG.criticalRate      = pct(AGG.totalCritical, AGG.totalEmails);
AGG.draftApprovalRate = pct(AGG.totalDraftsApproved, AGG.totalDraftsGenerated);
AGG.draftRejectionRate= pct(AGG.totalDraftsRejected, AGG.totalDraftsGenerated);
AGG.slaBreachRate     = AGG.totalSLABreaches > 0 && AGG.totalReplyRequired > 0
  ? pct(AGG.totalSLABreaches, AGG.totalReplyRequired) : 0;
AGG.slaComplianceRate = 100 - AGG.slaBreachRate;
AGG.aiAccuracyRate    = Math.round(AGG.avgConfidence * 100);

// ─────────────────────────────────────────────────────────────────────────
// 5. TREND DETECTION
// ─────────────────────────────────────────────────────────────────────────
// Split into first half and second half of the window
const half           = Math.floor(rows.length / 2);
const firstHalf      = rows.slice(0, half);
const secondHalf     = rows.slice(half);

const volumeTrend    = trend(
  avg(secondHalf.map(r => r.total_emails   || 0)),
  avg(firstHalf.map(r  => r.total_emails   || 0))
);
const criticalTrend  = trend(
  avg(secondHalf.map(r => r.critical_count || 0)),
  avg(firstHalf.map(r  => r.critical_count || 0))
);
const slaTrend       = trend(
  100 - pct(sum(secondHalf.map(r => r.sla_breach_count || 0)), sum(secondHalf.map(r => r.reply_required_count || 0))),
  100 - pct(sum(firstHalf.map(r  => r.sla_breach_count || 0)), sum(firstHalf.map(r  => r.reply_required_count || 0)))
);
const draftTrend     = trend(
  pct(sum(secondHalf.map(r => r.draft_approved_count || 0)), sum(secondHalf.map(r => r.draft_generated_count || 0))),
  pct(sum(firstHalf.map(r  => r.draft_approved_count || 0)), sum(firstHalf.map(r  => r.draft_generated_count || 0)))
);

// ─────────────────────────────────────────────────────────────────────────
// 6. ANOMALY DETECTION
// ─────────────────────────────────────────────────────────────────────────
const anomalies = [];

if (AGG.todayCritical > CFG.maxDailyCriticalNormal) {
  anomalies.push({
    type: 'CRITICAL_SPIKE',
    message: `Today had ${AGG.todayCritical} critical emails — above normal threshold of ${CFG.maxDailyCriticalNormal}`,
    severity: 'HIGH',
  });
}
if (AGG.todayEmails > CFG.maxDailyEmailsNormal) {
  anomalies.push({
    type: 'VOLUME_SPIKE',
    message: `Today received ${AGG.todayEmails} emails — above normal threshold of ${CFG.maxDailyEmailsNormal}`,
    severity: 'MEDIUM',
  });
}
if (AGG.slaComplianceRate < CFG.slaComplianceTarget) {
  anomalies.push({
    type: 'SLA_BELOW_TARGET',
    message: `SLA compliance ${AGG.slaComplianceRate}% is below target of ${CFG.slaComplianceTarget}%`,
    severity: 'HIGH',
  });
}
if (AGG.draftApprovalRate < CFG.draftApprovalTarget && AGG.totalDraftsGenerated > 5) {
  anomalies.push({
    type: 'LOW_DRAFT_APPROVAL',
    message: `Draft approval rate ${AGG.draftApprovalRate}% is below target of ${CFG.draftApprovalTarget}% — prompts may need tuning`,
    severity: 'MEDIUM',
  });
}
if (AGG.aiAccuracyRate < CFG.aiConfidenceTarget) {
  anomalies.push({
    type: 'LOW_AI_CONFIDENCE',
    message: `Average AI confidence ${AGG.aiAccuracyRate}% is below target of ${CFG.aiConfidenceTarget}%`,
    severity: 'MEDIUM',
  });
}
if (criticalTrend.dir === 'UP' && criticalTrend.delta > 20) {
  anomalies.push({
    type: 'CRITICAL_TRENDING_UP',
    message: `Critical email volume is trending up ${criticalTrend.delta}% week-over-week`,
    severity: 'MEDIUM',
  });
}

// ─────────────────────────────────────────────────────────────────────────
// 7. RECOMMENDATIONS ENGINE
// ─────────────────────────────────────────────────────────────────────────
const recommendations = [];

if (AGG.slaComplianceRate < CFG.slaComplianceTarget) {
  recommendations.push(`SLA compliance is ${AGG.slaComplianceRate}% — review emails marked BREACH in the dashboard and set up earlier warning alerts.`);
}
if (AGG.draftApprovalRate < CFG.draftApprovalTarget) {
  recommendations.push(`Draft approval rate is ${AGG.draftApprovalRate}% — consider reviewing the reply prompt generator voice profile to better match your communication style.`);
}
if (AGG.noiseFilterRate > 60) {
  recommendations.push(`${AGG.noiseFilterRate}% of emails are filtered as noise — consider adding more domains to the blocked list to reduce processing costs.`);
}
if (AGG.totalErrors > 5) {
  recommendations.push(`${AGG.totalErrors} pipeline errors this week — check the PostgreSQL eih_error_log table for patterns.`);
}
if (AGG.totalEscalations > 0) {
  recommendations.push(`${AGG.totalEscalations} escalations this week — review escalation patterns in the dashboard to identify recurring senders or domains.`);
}
if (AGG.avgConfidence < 0.75) {
  recommendations.push(`AI classification confidence averaged ${fmt(AGG.avgConfidence * 100, 0)}% — consider adding more few-shot examples to the classification prompt for low-performing domain categories.`);
}

// ─────────────────────────────────────────────────────────────────────────
// 8. DAILY VOLUME CHART DATA (for HTML email sparkline)
// ─────────────────────────────────────────────────────────────────────────
const maxDaily = Math.max(
  max(rows.map(r => r.total_emails   || 0)),
  1
);
const dailyChart = rows.map(r => ({
  date:     fmtDate(r.date),
  total:    Number(r.total_emails   || 0),
  critical: Number(r.critical_count || 0),
  high:     Number(r.high_count     || 0),
  medium:   Number(r.medium_count   || 0),
  low:      Number(r.low_count      || 0),
  noise:    Number(r.noise_count    || 0),
  bar:      barH(Number(r.total_emails || 0), maxDaily, 15),
}));

// ─────────────────────────────────────────────────────────────────────────
// 9. HTML EMAIL DIGEST
// ─────────────────────────────────────────────────────────────────────────
function buildHTML() {
  const headerColor = anomalies.some(a => a.severity === 'HIGH') ? '#E24B4A' : '#185FA5';
  const reportTitle = `${CFG.orgName} — Email Intelligence Report`;
  const reportPeriod = `${fmtDate(rows[0].date)} – ${fmtDate(rows[rows.length-1].date)}`;

  const statCard = (label, value, sub, color = '#185FA5') =>
    `<td style="padding:8px;text-align:center;background:#f8f9fa;border-radius:6px">
      <div style="font-size:22px;font-weight:700;color:${color}">${value}</div>
      <div style="font-size:11px;color:#666;margin-top:2px">${label}</div>
      ${sub ? `<div style="font-size:10px;color:#999;margin-top:1px">${sub}</div>` : ''}
    </td>`;

  const metricRow = (label, value, target, achieved) =>
    `<tr>
      <td style="padding:6px 0;font-size:13px;color:#333">${label}</td>
      <td style="padding:6px 0;font-size:13px;font-weight:600;text-align:right;color:${achieved ? '#3B6D11' : '#A32D2D'}">${value}</td>
      <td style="padding:6px 0;font-size:11px;color:#999;text-align:right">${target}</td>
    </tr>`;

  const anomalyBlock = anomalies.length > 0
    ? `<div style="background:#FFF3CD;border-left:4px solid #BA7517;padding:12px 16px;margin:16px 0;border-radius:0 6px 6px 0">
        <div style="font-size:13px;font-weight:600;color:#7D5A0A;margin-bottom:8px">⚠ Anomalies Detected</div>
        ${anomalies.map(a =>
          `<div style="font-size:12px;color:#5A3E00;margin-bottom:4px">• ${a.message}</div>`
        ).join('')}
       </div>` : '';

  const recBlock = recommendations.length > 0
    ? `<div style="margin-top:20px">
        <div style="font-size:14px;font-weight:600;color:#333;margin-bottom:10px">Recommendations</div>
        ${recommendations.map((r, i) =>
          `<div style="font-size:12px;color:#444;padding:6px 0;border-bottom:1px solid #eee">${i+1}. ${r}</div>`
        ).join('')}
       </div>` : '';

  const dailyRows = dailyChart.map(d =>
    `<tr>
      <td style="padding:5px 8px;font-size:12px;color:#555;white-space:nowrap">${d.date}</td>
      <td style="padding:5px 8px;font-size:12px;font-weight:600;text-align:right">${d.total}</td>
      <td style="padding:5px 8px;font-size:12px;color:#E24B4A;text-align:right">${d.critical || '—'}</td>
      <td style="padding:5px 8px;font-size:12px;color:#BA7517;text-align:right">${d.high || '—'}</td>
      <td style="padding:5px 8px;font-size:11px;font-family:monospace;color:#888">${d.bar}</td>
    </tr>`
  ).join('');

  return `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>${reportTitle}</title></head>
<body style="margin:0;padding:0;background:#f0f2f5;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif">
<div style="max-width:640px;margin:24px auto;background:#fff;border-radius:10px;overflow:hidden;border:1px solid #e0e0e0">

  <div style="background:${headerColor};padding:28px 32px">
    <div style="color:#fff;font-size:20px;font-weight:700">${reportTitle}</div>
    <div style="color:rgba(255,255,255,0.8);font-size:13px;margin-top:4px">${reportPeriod} · Generated ${now.toLocaleString('en-IN')}</div>
  </div>

  <div style="padding:24px 32px">

    <table style="width:100%;border-collapse:separate;border-spacing:8px;margin:-8px">
      <tr>
        ${statCard('Total emails', fmt(AGG.totalEmails), `${fmt(AGG.avgDailyEmails)}/day avg`)}
