// ═══════════════════════════════════════════════════════════════════════════
// LEARNING FEEDBACK PROCESSOR — v4.0 ADVANCED
// ─────────────────────────────────────────────────────────────────────────
// Triggered by the Approval Webhook node after every user action.
// Converts user decisions into structured learning signals that improve
// classification accuracy, draft quality, and priority calibration over time.
//
// Pipeline:
//   1.  Config (hardcoded — no env vars)
//   2.  Input normalization — handle all 5 action types
//   3.  Feedback signal extraction
//   4.  Classification accuracy assessment
//   5.  Draft quality assessment (EDIT_SEND → diff analysis)
//   6.  Learning example construction (for few-shot library)
//   7.  Priority calibration signal
//   8.  Domain-level accuracy tracking
//   9.  Sender-level reputation update payload
//  10.  Prompt improvement recommendations
//  11.  Reinforcement signal (positive / negative / corrective)
//  12.  PostgreSQL upsert payloads (3 tables)
//  13.  Structured output with routing flags
// ═══════════════════════════════════════════════════════════════════════════

// ─────────────────────────────────────────────────────────────────────────
// 1. CONFIG
// ─────────────────────────────────────────────────────────────────────────
const CFG = {
  orgName:    'PharmaOS',
  userEmail:  'jainakshatsunil@gmail.com',
  userName:   'Akshat Jain',

  // Minimum edit distance to count as a "significant edit"
  // below this = minor formatting, above = substantive correction
  significantEditThreshold: 50,

  // Score thresholds
  highConfidenceThreshold:  0.85,
  lowConfidenceThreshold:   0.60,

  // How much weight user corrections carry
  // vs historical accuracy when updating domain accuracy
  correctionWeight: 0.3,

  // Minimum examples before a domain's accuracy is considered reliable
  minExamplesForReliability: 10,
};

// ─────────────────────────────────────────────────────────────────────────
// 2. UTILITIES
// ─────────────────────────────────────────────────────────────────────────
function safeStr(v) {
  return typeof v === 'string' ? v.trim() : String(v || '');
}

function safeBool(v, def = false) {
  if (typeof v === 'boolean') return v;
  if (v === 'true'  || v === 1) return true;
  if (v === 'false' || v === 0) return false;
  return def;
}

function safeInt(v, def = 0) {
  const n = parseInt(v);
  return isNaN(n) ? def : n;
}

function safeFloat(v, def = 0) {
  const n = parseFloat(v);
  return isNaN(n) ? def : n;
}

// Edit distance (Levenshtein) — measures how much a draft was changed
function editDistance(a, b) {
  const la = (a || '').length;
  const lb = (b || '').length;
  if (la === 0) return lb;
  if (lb === 0) return la;
  // Cap at 2000 chars to avoid O(n²) on large drafts
  const as = a.substring(0, 2000);
  const bs = b.substring(0, 2000);
  const dp = Array.from({ length: as.length + 1 }, (_, i) =>
    Array.from({ length: bs.length + 1 }, (_, j) => (i === 0 ? j : j === 0 ? i : 0))
  );
  for (let i = 1; i <= as.length; i++) {
    for (let j = 1; j <= bs.length; j++) {
      if (as[i-1] === bs[j-1]) dp[i][j] = dp[i-1][j-1];
      else dp[i][j] = 1 + Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
    }
  }
  return dp[as.length][bs.length];
}

// Word-level diff — returns added/removed word count
function wordDiff(original, edited) {
  if (!original || !edited) return { added: 0, removed: 0, changed: false };
  const origWords = original.split(/\s+/).filter(Boolean);
  const editWords = edited.split(/\s+/).filter(Boolean);
  const origSet   = new Set(origWords);
  const editSet   = new Set(editWords);
  const added   = editWords.filter(w => !origSet.has(w)).length;
  const removed = origWords.filter(w => !editSet.has(w)).length;
  return { added, removed, changed: added > 0 || removed > 0 };
}

// Extract changed sections (which part of the draft was edited)
function identifyChangedSections(original, edited) {
  if (!original || !edited) return [];
  const sections   = [];
  const origLines  = original.split('\n');
  const editLines  = edited.split('\n');
  const maxLen     = Math.max(origLines.length, editLines.length);
  let changed      = false;

  for (let i = 0; i < maxLen; i++) {
    const o = origLines[i] || '';
    const e = editLines[i] || '';
    if (o !== e) {
      changed = true;
      // Classify which section was changed
      if (i === 0)                        sections.push('salutation');
      else if (i === 1 || i === 2)        sections.push('opening');
      else if (i >= maxLen - 3)           sections.push('closing_or_signature');
      else                                sections.push('body_paragraph_' + i);
    }
  }

  // Deduplicate section labels
  return [...new Set(sections)];
}

// ─────────────────────────────────────────────────────────────────────────
// 3. INPUT NORMALIZATION
// ─────────────────────────────────────────────────────────────────────────
const e = $input.first().json;

const action       = safeStr(e.action      || e._action       || '').toUpperCase();
const messageId    = safeStr(e.messageId   || e.message_id    || '');
const userId       = safeStr(e.userId      || e.user_id       || CFG.userName);
const editedReply  = safeStr(e.editedReply || e.edited_reply  || '');
const originalDraft= safeStr(e.draftReply  || e.draft_reply   || '');
const snoozeUntil  = e.snoozeUntil  || e.snooze_until  || null;
const escalateTo   = e.escalateTo   || e.escalate_to   || null;
const escalationNote = e.escalationNote || e.escalation_note || '';
const rejectionReason= e.rejectionReason|| e.rejection_reason|| '';

// Classification data
const priorityClass    = safeStr(e.priorityClass    || e.priority_class    || '');
const confidenceScore  = safeFloat(e.confidenceScore || e.confidence_score, 0.5);
const urgencyScore     = safeInt(e.urgencyScore      || e.urgency_score,    5);
const intent           = safeStr(e.intent            || '');
const sentiment        = safeStr(e.sentiment         || '');
const senderTier       = safeStr(e.senderTier        || e.sender_tier      || '');
const domainCategory   = safeStr(e.domainCategory    || e.domain_category  || '');
const domainSub        = safeStr(e.domainSubcategory || e.domain_subcategory|| '');
const senderEmail      = safeStr(e.senderEmail       || e.sender_email     || '');
const senderDomain     = safeStr(e.senderDomain      || e.sender_domain    || '');
const subject          = safeStr(e.subject           || '');
const bodyText         = safeStr(e.bodyText          || e.body_text        || '').substring(0, 1500);
const slaBucket        = safeStr(e.slaBucket         || e.sla_bucket       || '');
const legalFlag        = safeBool(e.legalFlag        || e.legal_flag);
const regFlag          = safeBool(e.regulatoryFlag   || e.regulatory_flag);
const finFlag          = safeBool(e.financialFlag    || e.financial_flag);
const secFlag          = safeBool(e.securityFlag     || e.security_flag);
const prelimScore      = safeInt(e.preliminaryScore  || e.preliminary_score, 0);
const draftQuality     = safeStr(e.draftQualityRating|| e.draft_quality_rating || '');
const overrideLog      = e.overrideLog || [];
const coercionLog      = e.coercionLog || [];
const apiModel         = safeStr(e.apiModel          || '');
const classifReason    = safeStr(e.classificationReason || '');
const emailSummary     = safeStr(e.emailSummary      || '');
const keyQuote         = safeStr(e.keyQuote          || '');

const now = new Date().toISOString();

// ─────────────────────────────────────────────────────────────────────────
// 4. FEEDBACK SIGNAL EXTRACTION
//    Maps each action to a learning signal type and strength
// ─────────────────────────────────────────────────────────────────────────
const SIGNAL_MAP = {
  APPROVE:    { type: 'POSITIVE',    strength: 1.0, classifFeedback: 'CONFIRMED',  draftFeedback: 'APPROVED_AS_IS' },
  EDIT_SEND:  { type: 'CORRECTIVE',  strength: 0.7, classifFeedback: 'CONFIRMED',  draftFeedback: 'EDITED_BEFORE_SEND' },
  REJECT:     { type: 'NEGATIVE',    strength: 0.8, classifFeedback: 'UNCERTAIN',  draftFeedback: 'REJECTED' },
  SNOOZE:     { type: 'DEFERRAL',    strength: 0.3, classifFeedback: 'TIMING',     draftFeedback: 'NOT_ACTIONED' },
  ESCALATE:   { type: 'ESCALATION',  strength: 0.9, classifFeedback: 'UNDER_RATED',draftFeedback: 'NOT_USED' },
};

const signal = SIGNAL_MAP[action] || { type: 'UNKNOWN', strength: 0, classifFeedback: 'UNKNOWN', draftFeedback: 'UNKNOWN' };

// ─────────────────────────────────────────────────────────────────────────
// 5. CLASSIFICATION ACCURACY ASSESSMENT
// ─────────────────────────────────────────────────────────────────────────
let classifAccurate      = null;
let classifCorrectedPriority = null;
let classifSignal        = signal.classifFeedback;
let classifNotes         = [];

// APPROVE = user agreed with classification → accurate
if (action === 'APPROVE') {
  classifAccurate = true;
  classifNotes.push('User approved without changes — classification confirmed accurate');
}

// EDIT_SEND = classification was correct enough to act on, draft needed tweaking
if (action === 'EDIT_SEND') {
  classifAccurate = true;
  classifNotes.push('User edited draft and sent — classification confirmed, draft needed adjustment');
}

// REJECT = could be draft issue or priority misclassification
if (action === 'REJECT') {
  classifAccurate = null; // uncertain — might be draft issue not classification
  if (rejectionReason) {
    const reason = rejectionReason.toLowerCase();
    if (reason.includes('wrong priority') || reason.includes('not urgent') || reason.includes('not critical')) {
      classifAccurate = false;
      classifSignal   = 'PRIORITY_TOO_HIGH';
      classifNotes.push('User indicated priority was too high: ' + rejectionReason);
    } else if (reason.includes('noise') || reason.includes('not relevant') || reason.includes('spam')) {
      classifAccurate = false;
      classifSignal   = 'SHOULD_BE_NOISE';
      classifNotes.push('User indicated email should be noise/irrelevant');
    } else if (reason.includes('draft') || reason.includes('reply') || reason.includes('tone')) {
      classifAccurate = true; // classification right, draft wrong
      classifSignal   = 'DRAFT_QUALITY_ISSUE';
      classifNotes.push('Rejection was about draft quality, not classification');
    }
  }
}

// ESCALATE = user decided priority was too low → classification under-rated
if (action === 'ESCALATE') {
  classifAccurate  = false;
  classifSignal    = 'PRIORITY_TOO_LOW';
  classifNotes.push('User escalated — AI classification under-rated the urgency');
  // Infer what the user thought the priority should have been
  const ORDER = { CRITICAL:0, HIGH:1, MEDIUM:2, LOW:3, NOISE:4 };
  const currentOrder = ORDER[priorityClass] || 2;
  if (currentOrder > 0) {
    const corrected = Object.keys(ORDER).find(k => ORDER[k] === currentOrder - 1);
    classifCorrectedPriority = corrected || 'CRITICAL';
    classifNotes.push('Inferred corrected priority: ' + classifCorrectedPriority);
  }
}

// SNOOZE = email is real but not urgent right now → timing issue
if (action === 'SNOOZE') {
  classifAccurate = null;
  classifNotes.push('User snoozed — email is real but not the right time');
}

// Confidence calibration check
const confidenceWasHighAndWrong = classifAccurate === false && confidenceScore >= CFG.highConfidenceThreshold;
const confidenceWasLowAndRight  = classifAccurate === true  && confidenceScore <= CFG.lowConfidenceThreshold;

if (confidenceWasHighAndWrong) {
  classifNotes.push('HIGH CONFIDENCE MISCALIBRATION: model was ' + Math.round(confidenceScore*100) + '% confident but was wrong');
}
if (confidenceWasLowAndRight) {
  classifNotes.push('Low confidence but correct — model is under-confident on this pattern');
}

// ─────────────────────────────────────────────────────────────────────────
// 6. DRAFT QUALITY ASSESSMENT (deep analysis for EDIT_SEND)
// ─────────────────────────────────────────────────────────────────────────
let draftAnalysis = null;

if (action === 'EDIT_SEND' && editedReply && originalDraft) {
  const charDist    = editDistance(originalDraft, editedReply);
  const wdiff       = wordDiff(originalDraft, editedReply);
  const sections    = identifyChangedSections(originalDraft, editedReply);
  const isSignif    = charDist >= CFG.significantEditThreshold;
  const pctChanged  = originalDraft.length > 0
    ? Math.round(charDist / originalDraft.length * 100) : 0;

  // Classify what type of edit was made
  let editType = 'MINOR_FORMATTING';
  if (sections.includes('salutation'))              editType = 'SALUTATION_CHANGED';
  else if (sections.includes('closing_or_signature'))editType = 'CLOSING_CHANGED';
  else if (sections.some(s => s.startsWith('body')) && isSignif) editType = 'BODY_SUBSTANTIALLY_REWRITTEN';
  else if (isSignif)                                editType = 'SIGNIFICANT_EDIT';
  else if (wdiff.added > 20)                        editType = 'CONTENT_ADDED';
  else if (wdiff.removed > 20)                      editType = 'CONTENT_REMOVED';

  // Check if placeholders were filled in (expected behaviour)
  const needsInputFilled = originalDraft.includes('[NEEDS INPUT:') &&
    !editedReply.includes('[NEEDS INPUT:');
  const verifyFilled     = originalDraft.includes('[VERIFY:') &&
    !editedReply.includes('[VERIFY:');
  const warningsRemoved  = originalDraft.includes('[WARNING:') &&
    !editedReply.includes('[WARNING:');

  draftAnalysis = {
    charEditDistance:       charDist,
    wordsAdded:             wdiff.added,
    wordsRemoved:           wdiff.removed,
    pctChanged,
    isSignificantEdit:      isSignif,
    editType,
    sectionsChanged:        sections,
    placeholdersFilled:     needsInputFilled || verifyFilled,
    needsInputFilled,
    verifyFilled,
    warningsRemoved,
    draftWasUsable:         !isSignif, // if minor edit, draft was mostly good
    finalReplyLength:       editedReply.length,
    originalDraftLength:    originalDraft.length,
  };
} else if (action === 'APPROVE') {
  draftAnalysis = {
    charEditDistance:    0,
    pctChanged:          0,
    isSignificantEdit:   false,
    editType:            'NO_EDIT',
    sectionsChanged:     [],
    draftWasUsable:      true,
  };
} else if (action === 'REJECT') {
  draftAnalysis = {
    charEditDistance:    null,
    pctChanged:          null,
    isSignificantEdit:   null,
    editType:            'REJECTED',
    sectionsChanged:     [],
    draftWasUsable:      false,
    rejectionReason,
  };
}

// ─────────────────────────────────────────────────────────────────────────
// 7. LEARNING EXAMPLE CONSTRUCTION
//    Builds a structured few-shot example to store in eih_learning_examples
//    High-quality examples feed back into the classification prompt
// ─────────────────────────────────────────────────────────────────────────
let learningExample     = null;
let shouldStoreLearning = false;

// Only store high-value learning examples
const isHighValueSignal =
  // Confirmed critical classification
  (action === 'APPROVE' && priorityClass === 'CRITICAL') ||
  // Human corrected a classification
  (action === 'ESCALATE') ||
  // Human rejected with a stated reason
  (action === 'REJECT' && rejectionReason.length > 10) ||
  // Edit was substantial — reveals what the AI got wrong in the draft
  (action === 'EDIT_SEND' && draftAnalysis?.isSignificantEdit) ||
  // High confidence but wrong
  confidenceWasHighAndWrong;

if (isHighValueSignal && messageId && subject) {
  shouldStoreLearning = true;

  learningExample = {
    // Identity
    message_id:         messageId,
    subject:            subject.substring(0, 255),
    body_excerpt:       bodyText.substring(0, 800),
    sender_email:       senderEmail,
    sender_domain:      senderDomain,
    sender_tier:        senderTier,
    domain_category:    domainCategory,
    domain_subcategory: domainSub,

    // AI output
    ai_priority_class:       priorityClass,
    ai_confidence_score:     confidenceScore,
    ai_urgency_score:        urgencyScore,
    ai_intent:               intent,
    ai_sentiment:            sentiment,
    ai_sla_bucket:           slaBucket,
    ai_classification_reason:classifReason.substring(0, 500),
    ai_key_quote:            keyQuote.substring(0, 300),
    ai_model:                apiModel,
    ai_preliminary_score:    prelimScore,

    // Human feedback
    human_action:            action,
    human_priority_class:    classifCorrectedPriority || priorityClass,
    classification_accurate: classifAccurate,
    classification_signal:   classifSignal,
    classification_notes:    classifNotes.join(' | ').substring(0, 500),

    // Draft feedback
    draft_quality_rating:    draftQuality,
    draft_edit_type:         draftAnalysis?.editType || null,
    draft_pct_changed:       draftAnalysis?.pctChanged ?? null,
    draft_was_usable:        draftAnalysis?.draftWasUsable ?? null,
    rejection_reason:        rejectionReason.substring(0, 255),

    // Risk flags
    legal_flag:              legalFlag,
    regulatory_flag:         regFlag,
    financial_flag:          finFlag,
    security_flag:           secFlag,

    // Metadata
    feedback_type:           signal.type,
    feedback_strength:       signal.strength,
    override_log:            JSON.stringify(overrideLog).substring(0, 500),
    confidence_miscalibrated:confidenceWasHighAndWrong || confidenceWasLowAndRight,
    actioned_by:             userId,
    feedback_at:             now,

    // Quality score for the example itself (higher = more valuable for training)
    example_quality_score:
      (isHighValueSignal              ? 40 : 0) +
      (classifAccurate === false      ? 30 : 0) +  // corrections are most valuable
      (classifAccurate === true       ? 15 : 0) +  // confirmations are useful too
      (confidenceWasHighAndWrong      ? 20 : 0) +  // miscalibration is critical to fix
      (rejectionReason.length > 20    ? 10 : 0) +  // explained rejections are gold
      (draftAnalysis?.isSignificantEdit? 10 : 0) +
      Math.round(Math.min(keyQuote.length / 5, 10)),// key quote adds context
  };
}

// ─────────────────────────────────────────────────────────────────────────
// 8. PRIORITY CALIBRATION SIGNAL
//    Used to track if the model is systematically over/under rating
//    certain domain × sender tier combinations
// ─────────────────────────────────────────────────────────────────────────
const calibrationSignal = {
  domain_category:    domainCategory,
  sender_tier:        senderTier,
  ai_priority:        priorityClass,
  human_priority:     classifCorrectedPriority || (classifAccurate ? priorityClass : null),
  was_correct:        classifAccurate,
  direction:          classifSignal === 'PRIORITY_TOO_HIGH' ? 'OVER_RATED'
                    : classifSignal === 'PRIORITY_TOO_LOW'  ? 'UNDER_RATED'
                    : classifSignal === 'CONFIRMED'          ? 'CORRECT'
                    : 'UNKNOWN',
  confidence:         confidenceScore,
  feedback_at:        now,
};

// ─────────────────────────────────────────────────────────────────────────
// 9. SENDER REPUTATION UPDATE PAYLOAD
//    Updates eih_sender_registry with this interaction
// ─────────────────────────────────────────────────────────────────────────
const senderReputationUpdate = {
  sender_email:           senderEmail,
  sender_domain:          senderDomain,
  sender_name:            safeStr(e.senderName || e.sender_name || ''),
  last_action:            action,
  last_action_at:         now,
  // Increment counters (handled in PostgreSQL with ON CONFLICT DO UPDATE)
  emails_approved:        action === 'APPROVE'   ? 1 : 0,
  emails_edited:          action === 'EDIT_SEND' ? 1 : 0,
  emails_rejected:        action === 'REJECT'    ? 1 : 0,
  emails_snoozed:         action === 'SNOOZE'    ? 1 : 0,
  emails_escalated:       action === 'ESCALATE'  ? 1 : 0,
  // Priority boost / reduction based on user behaviour
  // If user keeps approving criticals from this domain → boost
  // If user keeps rejecting from this domain → reduce
  priority_adjustment:    action === 'APPROVE'  && priorityClass === 'CRITICAL' ?  1
                        : action === 'ESCALATE'                                 ?  2
                        : action === 'REJECT'   && rejectionReason.toLowerCase().includes('not urgent') ? -1
                        : 0,
};

// ─────────────────────────────────────────────────────────────────────────
// 10. PROMPT IMPROVEMENT RECOMMENDATIONS
//     Specific, actionable prompt tweaks based on the feedback pattern
// ─────────────────────────────────────────────────────────────────────────
const promptRecommendations = [];

if (classifSignal === 'PRIORITY_TOO_LOW' && domainCategory) {
  promptRecommendations.push({
    type:       'CLASSIFICATION_PROMPT',
    priority:   'HIGH',
    area:       'domain_priority',
    suggestion: `Increase minimum priority for ${domainCategory}/${domainSub} emails — user escalated from ${priorityClass}. Consider adding ${senderDomain} to PRIORITY_BOOST_DOMAINS.`,
  });
}

if (classifSignal === 'SHOULD_BE_NOISE' && domainCategory !== 'AUTOMATED') {
  promptRecommendations.push({
    type:       'ENRICHMENT_CONFIG',
    priority:   'MEDIUM',
    area:       'noise_detection',
    suggestion: `Domain ${senderDomain} is generating emails the user considers irrelevant. Consider adding to BLOCKED_DOMAINS or adjusting noise detection rules.`,
  });
}

if (confidenceWasHighAndWrong) {
  promptRecommendations.push({
    type:       'CLASSIFICATION_PROMPT',
    priority:   'CRITICAL',
    area:       'calibration',
    suggestion: `Model was ${Math.round(confidenceScore*100)}% confident but the classification was wrong for ${domainCategory}/${intent}. Add this as a negative few-shot example to the classification prompt.`,
  });
}

if (draftAnalysis?.editType === 'BODY_SUBSTANTIALLY_REWRITTEN' && domainCategory) {
  promptRecommendations.push({
    type:       'REPLY_PROMPT',
    priority:   'HIGH',
    area:       'draft_quality',
    suggestion: `User substantially rewrote the draft body for ${domainCategory}/${intent} emails. Review voice profile and intent framework for this combination. Pct changed: ${draftAnalysis.pctChanged}%.`,
  });
}

if (draftAnalysis?.editType === 'SALUTATION_CHANGED') {
  promptRecommendations.push({
    type:       'REPLY_PROMPT',
    priority:   'LOW',
    area:       'formality',
    suggestion: `User changed the salutation for ${senderTier} sender in ${domainCategory}. Check formality selection logic in the reply prompt generator.`,
  });
}

if (overrideLog && overrideLog.length > 2) {
  promptRecommendations.push({
    type:       'CLASSIFICATION_PROMPT',
    priority:   'MEDIUM',
    area:       'override_frequency',
    suggestion: `${overrideLog.length} hard overrides fired for this email — the prompt scoring may need re-calibration for ${domainCategory} domain to reduce reliance on override rules.`,
  });
}

// ─────────────────────────────────────────────────────────────────────────
// 11. REINFORCEMENT SIGNAL SUMMARY
// ─────────────────────────────────────────────────────────────────────────
const reinforcement = {
  // Overall signal
  signalType:        signal.type,
  signalStrength:    signal.strength,
  isPositive:        signal.type === 'POSITIVE',
  isNegative:        signal.type === 'NEGATIVE' || signal.type === 'ESCALATION',
  isCorrective:      signal.type === 'CORRECTIVE',

  // What to reinforce / penalize
  classificationCorrectness: classifAccurate,
  draftUsability:            draftAnalysis?.draftWasUsable ?? null,
  priorityDirection:         calibrationSignal.direction,

  // Composite learning score (0–100)
  // Higher = more valuable learning signal
  learningValue:
    Math.round(
      (signal.strength * 40) +
      (classifAccurate === false    ? 30 : 0) +
      (draftAnalysis?.isSignificantEdit? 20 : 0) +
      (confidenceWasHighAndWrong    ? 10 : 0)
    ),
};

// ─────────────────────────────────────────────────────────────────────────
// 12. POSTGRESQL PAYLOADS (3 tables)
// ─────────────────────────────────────────────────────────────────────────

// A) eih_action_log — primary action record
const actionLogPayload = {
  message_id:          messageId,
  action,
  user_id:             userId,
  edited_reply:        action === 'EDIT_SEND' ? editedReply.substring(0, 10000) : null,
  snooze_until:        action === 'SNOOZE'    ? snoozeUntil : null,
  escalate_to:         action === 'ESCALATE'  ? escalateTo  : null,
  escalation_note:     action === 'ESCALATE'  ? escalationNote.substring(0, 500) : null,
  rejection_reason:    action === 'REJECT'    ? rejectionReason.substring(0, 255) : null,
  email_priority_class:priorityClass,
  email_sla_bucket:    slaBucket,
  // Learning fields
  classification_accurate: classifAccurate,
  classification_signal:   classifSignal,
  draft_edit_pct:          draftAnalysis?.pctChanged ?? null,
  draft_edit_type:         draftAnalysis?.editType   || null,
  learning_value:          reinforcement.learningValue,
  feedback_strength:       signal.strength,
  action_at:               now,
};

// B) eih_learning_examples — curated examples for few-shot improvement
// (only when shouldStoreLearning = true)
const learningExamplePayload = shouldStoreLearning ? learningExample : null;

// C) eih_emails — update processing status
const emailStatusPayload = {
  message_id:        messageId,
  processing_status: action === 'APPROVE'   ? 'SENT'
                   : action === 'EDIT_SEND' ? 'SENT'
                   : action === 'REJECT'    ? 'DISMISSED'
                   : action === 'SNOOZE'    ? 'SNOOZED'
                   : action === 'ESCALATE'  ? 'ESCALATED'
                   : 'CLASSIFIED',
  updated_at:        now,
};

// ─────────────────────────────────────────────────────────────────────────
// 13. ROUTING FLAGS
// ─────────────────────────────────────────────────────────────────────────
const routing = {
  // Does downstream need to send an email via Gmail?
  sendEmail:        action === 'APPROVE' || action === 'EDIT_SEND',
  emailBody:        action === 'EDIT_SEND' ? editedReply : originalDraft,

  // Does this need to be stored as a learning example?
  storeLearning:    shouldStoreLearning,

  // Does this trigger a Slack notification?
  notifySlack:      action === 'ESCALATE' || (action === 'REJECT' && priorityClass === 'CRITICAL'),

  // Should it update sender reputation?
  updateSender:     senderEmail.length > 0,

  // Is this worth logging a prompt recommendation?
  hasPromptRec:     promptRecommendations.length > 0,

  // Does the prompt library need refresh? (accumulates over time)
  triggerPromptRefresh: confidenceWasHighAndWrong
    || classifSignal === 'PRIORITY_TOO_LOW'
    || classifSignal === 'SHOULD_BE_NOISE',
};

// ─────────────────────────────────────────────────────────────────────────
// 14. OUTPUT
// ─────────────────────────────────────────────────────────────────────────
return [{ json: {
  // ── Core action identity ──
  messageId,
  action,
  userId,
  processedAt: now,

  // ── Feedback signals ──
  signalType:              signal.type,
  signalStrength:          signal.strength,
  classifFeedback:         signal.classifFeedback,
  draftFeedback:           signal.draftFeedback,

  // ── Classification assessment ──
  classificationAccurate:       classifAccurate,
  classificationSignal:         classifSignal,
  classificationCorrectedPriority: classifCorrectedPriority,
  classificationNotes:          classifNotes,
  confidenceWasHighAndWrong,
  confidenceWasLowAndRight,

  // ── Draft analysis ──
  draftAnalysis,

  // ── Calibration ──
  calibrationSignal,

  // ── Learning example ──
  shouldStoreLearning,
  learningExample:         learningExamplePayload,
  learningValue:           reinforcement.learningValue,

  // ── Sender reputation ──
  senderReputationUpdate,

  // ── Reinforcement ──
  reinforcement,

  // ── Prompt recommendations ──
  promptRecommendations,
  hasPromptRecommendations: promptRecommendations.length > 0,

  // ── DB payloads ──
  actionLogPayload,
  learningExamplePayload,
  emailStatusPayload,

  // ── Routing flags ──
  ...routing,

  // ── Pass-through for downstream nodes ──
  priorityClass,
  slaBucket,
  senderEmail,
  senderDomain,
  senderName:    safeStr(e.senderName || e.sender_name || ''),
  subject,
  emailSummary,
  escalateTo,
  escalationNote,
  snoozeUntil,
  legalFlag,
  regulatoryFlag: regFlag,
  financialFlag:  finFlag,
  securityFlag:   secFlag,
  apiModel,
  domainCategory,
  threadId:      safeStr(e.threadId || e.thread_id || ''),
  draftReply:    originalDraft,
  editedReply:   action === 'EDIT_SEND' ? editedReply : null,
}}];

const e = $input.first().json;
const now = new Date().toISOString();

const rawMsg = (e.message || e.error?.message || JSON.stringify(e) || '').toLowerCase();
const statusCode = e.statusCode || e.error?.statusCode || e.httpCode || 0;

// Classify error severity
let severity, shouldRetry, retryDelayMs, maxRetries;

if (statusCode === 429 || rawMsg.includes('429') || rawMsg.includes('rate limit') || rawMsg.includes('too many requests')) {
  severity = 'RATE_LIMIT'; shouldRetry = true; retryDelayMs = 65000; maxRetries = 3;
} else if (statusCode === 401 || statusCode === 403 || rawMsg.includes('unauthorized') || rawMsg.includes('forbidden') || rawMsg.includes('api key') || rawMsg.includes('auth')) {
  severity = 'AUTH_FAILURE'; shouldRetry = false; retryDelayMs = 0; maxRetries = 0;
} else if (statusCode >= 500 || rawMsg.includes('timeout') || rawMsg.includes('econnreset') || rawMsg.includes('econnrefused') || rawMsg.includes('etimedout') || rawMsg.includes('socket hang up')) {
  severity = 'TIMEOUT'; shouldRetry = true; retryDelayMs = 8000; maxRetries = 3;
} else if (rawMsg.includes('database') || rawMsg.includes('sql') || rawMsg.includes('postgres') || rawMsg.includes('connection pool')) {
  severity = 'DB_ERROR'; shouldRetry = true; retryDelayMs = 5000; maxRetries = 2;
} else if (rawMsg.includes('claude') || rawMsg.includes('anthropic') || rawMsg.includes('model') || rawMsg.includes('overloaded')) {
  severity = 'AI_ERROR'; shouldRetry = true; retryDelayMs = 30000; maxRetries = 2;
} else if (rawMsg.includes('gmail') || rawMsg.includes('oauth') || rawMsg.includes('token expired')) {
  severity = 'GMAIL_ERROR'; shouldRetry = false; retryDelayMs = 0; maxRetries = 0;
} else if (rawMsg.includes('webhook') || rawMsg.includes('dashboard') || rawMsg.includes('enotfound')) {
  severity = 'WEBHOOK_ERROR'; shouldRetry = true; retryDelayMs = 10000; maxRetries = 2;
} else {
  severity = 'GENERAL_ERROR'; shouldRetry = true; retryDelayMs = 5000; maxRetries = 1;
}

const alertRequired = ['AUTH_FAILURE', 'DB_ERROR', 'GMAIL_ERROR'].includes(severity);
const criticalAlert = severity === 'AUTH_FAILURE'; // auth failures stop ALL processing

return [{ json: {
  errorId:        `err_${Date.now()}_${Math.random().toString(36).substring(2,7)}`,
  severity,
  shouldRetry,
  retryDelayMs,
  maxRetries,
  alertRequired,
  criticalAlert,
  statusCode,
  // Source email context
  emailId:        e.messageId || e.gmailMessageId || 'UNKNOWN',
  subject:        e.subject   || 'unknown',
  senderEmail:    e.senderEmail  || null,
  senderDomain:   e.senderDomain || null,
  priorityClass:  e.priorityClass || null,
  // Error details
  errorMessage:   e.message   || e.error?.message  || 'Unknown error',
  errorCode:      e.code      || e.error?.code     || e.statusCode || 'UNKNOWN',
  processingStage: e.processingStatus || 'UNKNOWN',
  rawErrorSample: JSON.stringify(e).substring(0, 500),
  errorAt:        now,
  processingStatus: 'ERROR_LOGGED'
}}];

const email = $('Parse and Normalize Email').first().json;

// Pull count from the Postgres node
const dbRow = $('PostgreSQL Dedup Lookup').first().json;
const cnt = Number(dbRow?.cnt ?? 0);
const isDuplicate = cnt > 0;

return [{
  json: {
    ...email,            // all email fields including isLikelyNoise, senderEmail etc.
    isDuplicate,
    existingCount: cnt,
    dedupCheckedAt: new Date().toISOString()
  }
}];

const email = $input.first().json;

const MODELS = {
  CRITICAL: [
    { id: 'anthropic/claude-sonnet-4-5', ctxWindow: 200000, inputCost: 3.00, outputCost: 15.00, maxOutput: 1500, provider: 'Anthropic' },
    { id: 'openai/gpt-4o',               ctxWindow: 128000, inputCost: 2.50, outputCost: 10.00, maxOutput: 1500, provider: 'OpenAI' },
    { id: 'google/gemini-pro-1.5',        ctxWindow: 1000000,inputCost: 1.25, outputCost: 5.00,  maxOutput: 1500, provider: 'Google' },
  ],
  STANDARD: [
    { id: 'openai/gpt-4o-mini',                    ctxWindow: 128000, inputCost: 0.15, outputCost: 0.60, maxOutput: 1500, provider: 'OpenAI' },
    { id: 'google/gemini-flash-1.5',               ctxWindow: 1000000,inputCost: 0.075,outputCost: 0.30, maxOutput: 1500, provider: 'Google' },
    { id: 'meta-llama/llama-3.3-70b-instruct',     ctxWindow: 131072, inputCost: 0.20, outputCost: 0.20, maxOutput: 1500, provider: 'Meta' },
  ],
  LOW: [
    { id: 'openai/gpt-4o-mini',      ctxWindow: 128000, inputCost: 0.15, outputCost: 0.60, maxOutput: 800, provider: 'OpenAI' },
    { id: 'google/gemini-flash-1.5', ctxWindow: 1000000,inputCost: 0.075,outputCost: 0.30, maxOutput: 800, provider: 'Google' },
  ],
};

function selectModelTier(e) {
  const score  = e.preliminaryScore || 0;
  const dom    = e.domainCategory   || 'UNKNOWN';
  const risk   = e.domainRiskLevel  || 0;
  const critKW = (e.criticalKeywords || []).length;

  if (e.legalFlag || e.regulatoryFlag)                    return 'CRITICAL';
  if (risk >= 4)                                          return 'CRITICAL';
  if (['REGULATORY','LEGAL'].includes(dom))               return 'CRITICAL';
  if (e.isVIP && score >= 60)                             return 'CRITICAL';
  if (critKW > 0)                                         return 'CRITICAL';
  if (e.isHighStakes)                                     return 'CRITICAL';
  if (e.financialFlag && score >= 70)                     return 'CRITICAL';
  if (e.securityFlag)                                     return 'CRITICAL';
  if (dom === 'FINANCIAL' && score >= 65)                 return 'CRITICAL';
  if (e.isLikelyNoise || (score <= 20 && !e.isVIP))      return 'LOW';
  return 'STANDARD';
}

const forceModel = $env.FORCE_MODEL || '';
const costMode   = ($env.COST_MODE  || 'balanced').toLowerCase();

let selectedModel, modelTier;
if (forceModel) {
  selectedModel = { id: forceModel, maxOutput: 1500, provider: 'unknown', inputCost: 0, outputCost: 0, ctxWindow: 128000 };
  modelTier = 'FORCED';
} else {
  modelTier = selectModelTier(email);
  const pool = MODELS[modelTier] || MODELS['STANDARD'];
  selectedModel = costMode === 'economy'
    ? [...pool].sort((a,b) => a.inputCost - b.inputCost)[0]
    : costMode === 'performance'
    ? [...pool].sort((a,b) => b.inputCost - a.inputCost)[0]
    : pool[0];
}

function estimateTokens(text) { return Math.ceil((text || '').length / 4); }

let systemPrompt = email.classificationSystemPrompt || '';
let userPrompt   = email.classificationUserPrompt   || '';
const sysTokens  = estimateTokens(systemPrompt);
const userTokens = estimateTokens(userPrompt);
const totalIn    = sysTokens + userTokens;
const ctxWindow  = selectedModel.ctxWindow || 128000;
const safeMargin = 2000;
const available  = ctxWindow - totalIn - safeMargin;
let bodyTruncated = false;

if (available < selectedModel.maxOutput && totalIn > ctxWindow * 0.7) {
  const bStart = userPrompt.indexOf('EMAIL BODY');
  const bEnd   = userPrompt.indexOf('END OF EMAIL BODY');
  if (bStart !== -1 && bEnd !== -1) {
    const maxChars = Math.max(500, available * 4 - 500);
    const section  = userPrompt.substring(bStart, bEnd);
    userPrompt = userPrompt.substring(0, bStart) + section.substring(0, maxChars) + '\n[body truncated — token budget]\n' + userPrompt.substring(bEnd);
    bodyTruncated = true;
  }
}

const PROVIDER_PREFS = {
  CRITICAL: { order: ['Anthropic','OpenAI','Google'], allow_fallbacks: true, data_collection: 'deny' },
  STANDARD: { order: ['OpenAI','Google','Anthropic'], allow_fallbacks: true, data_collection: 'deny' },
  LOW:      { order: ['Google','OpenAI'],             allow_fallbacks: true, data_collection: 'deny' },
  FORCED:   { allow_fallbacks: false,                                        data_collection: 'deny' },
};

const providerPrefs = PROVIDER_PREFS[modelTier] || PROVIDER_PREFS['STANDARD'];
const temperature   = email.classificationTemperature ?? parseFloat($env.AI_TEMPERATURE_CLASS || '0.05');

const requestBody = {
  model:           selectedModel.id,
  temperature,
  max_tokens:      selectedModel.maxOutput,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: userPrompt   },
  ],
  response_format: { type: 'json_object' },
  provider:        providerPrefs,
  transforms:      ['middle-out'],
};

const estimatedInputCost  = (totalIn / 1000000) * selectedModel.inputCost;
const estimatedOutputCost = (selectedModel.maxOutput / 1000000) * selectedModel.outputCost;
const estimatedTotalCost  = estimatedInputCost + estimatedOutputCost;

return [{ json: {
  ...email,
  _openRouterBody:       JSON.stringify(requestBody),
  _openRouterUrl:        'https://openrouter.ai/api/v1/chat/completions',
  _routingTier:          modelTier,
  _selectedModel:        selectedModel.id,
  _selectedProvider:     selectedModel.provider,
  _totalInputTokensEst:  totalIn,
  _maxOutputTokens:      selectedModel.maxOutput,
  _ctxWindow:            ctxWindow,
  _bodyWasTruncated:     bodyTruncated,
  _estimatedCostUSD:     Math.round(estimatedTotalCost * 100000) / 100000,
  _requestId:            'cls_' + (email.messageId || '') + '_' + Date.now(),
  _retryAttempt:         0,
  _retryConfig:          { maxAttempts: 3, baseDelayMs: 1000, maxDelayMs: 16000, backoffFactor: 2 },
  processingStatus:      'API_REQUEST_BUILT',
}}];

// ═══════════════════════════════════════════════════════════════════════════
// BUILD PUSH PAYLOAD — v4.0 (HARDCODED — no environment variables)
// Paste this into the Code node: "Build Push Payload"
// Mode: Run Once For Each Item
// ═══════════════════════════════════════════════════════════════════════════
console.log('INPUT KEYS:', Object.keys($input.first().json).join(', '));
console.log('messageId:', $input.first().json.messageId);
const e = $input.first().json;

// ─────────────────────────────────────────────────────────────────────────
// ★ EDIT THESE VALUES — your actual credentials
// ─────────────────────────────────────────────────────────────────────────
const DASHBOARD_URL = 'http://host.docker.internal:3001/api/emails/pending';
const DASHBOARD_SECRET = 'my-secret-2026';
const MAX_RETRIES      = 3;
const BASE_DELAY_MS    = 2000;
// ─────────────────────────────────────────────────────────────────────────

// ── Skip push if URL is blank
if (!DASHBOARD_URL) {
  return [{ json: {
    ...e,
    _skipPush:   true,
    _skipReason: 'DASHBOARD_URL not configured',
  }}];
}

// ── Idempotency key — prevents duplicate dashboard entries on retry
// Robust pushKey — never empty
const msgId  = e.messageId   || e.message_id   || '';
const ts     = e.classifiedAt|| e.receivedAt   || e.received_at || Date.now().toString();

const pushKey = 'push_' + (
  msgId.length > 0
    ? msgId.replace(/[^a-zA-Z0-9]/g, '').substring(0, 24)
    : Math.random().toString(36).substring(2, 14)
) + '_' + ts.toString().replace(/[^0-9]/g, '').substring(0, 14);

// ── Priority display metadata (used by dashboard for colors)
const PRIORITY_META = {
  CRITICAL: { color: '#E24B4A', bg: '#FCEBEB', slaLabel: '≤ 2h'  },
  HIGH:     { color: '#BA7517', bg: '#FAEEDA', slaLabel: '≤ 8h'  },
  MEDIUM:   { color: '#378ADD', bg: '#E6F1FB', slaLabel: '≤ 24h' },
  LOW:      { color: '#639922', bg: '#EAF3DE', slaLabel: '≤ 5d'  },
  NOISE:    { color: '#888780', bg: '#F1EFE8', slaLabel: 'None'  },
};
const pm = PRIORITY_META[e.priorityClass] || PRIORITY_META['MEDIUM'];

// ── SLA elapsed % — pre-computed so dashboard renders without math
function slaElapsed() {
  if (!e.slaDeadline || !e.receivedAt) return null;
  const total   = new Date(e.slaDeadline) - new Date(e.receivedAt);
  const elapsed = Date.now() - new Date(e.receivedAt);
  if (total <= 0) return 100;
  return Math.min(100, Math.max(0, Math.round(elapsed / total * 100)));
}

// ── Risk flag array for dashboard badge row
const riskFlags = [
  e.legalFlag                 && 'LEGAL',
  e.regulatoryFlag            && 'REGULATORY',
  e.financialFlag             && 'FINANCIAL',
  e.securityFlag              && 'SECURITY',
  e.hrFlag                    && 'HR',
  e.privilegeFlag             && 'PRIVILEGED',
  e.preservationRequired      && 'PRESERVE',
  e.boardNotificationRequired && 'BOARD',
].filter(Boolean);

// ── Draft quality badge for dashboard
const QUALITY_BADGE = {
  CONFIDENT:    { label: 'AI confident',  color: '#639922' },
  PARTIAL:      { label: 'Needs review',  color: '#BA7517' },
  NEEDS_REVIEW: { label: 'Manual review', color: '#E24B4A' },
};
const qb = QUALITY_BADGE[e.draftQualityRating] || QUALITY_BADGE['NEEDS_REVIEW'];

// ── Full payload (65 fields)
const payload = {

  // Identity
  messageId:                  e.messageId,
  threadId:                   e.threadId,

  // Sender
  senderName:                 e.senderName,
  senderEmail:                e.senderEmail,
  senderDomain:               e.senderDomain,

  // Content
  subject:                    e.subject,
  bodyText:                   (e.bodyText || '').substring(0, 3000),
  receivedAt:                 e.receivedAt,
  wordCount:                  e.wordCount       || 0,
  hasAttachment:              e.hasAttachment   || false,
  attachmentNames:            e.attachmentNames || [],
  attachmentTypes:            e.attachmentTypes || [],
  language:                   e.language        || 'en',

  // Classification
  priorityClass:              e.priorityClass,
  priorityColor:              pm.color,
  priorityBg:                 pm.bg,
  urgencyScore:               e.urgencyScore    || 5,
  confidenceScore:            e.confidenceScore || 0.5,
  slaBucket:                  e.slaBucket,
  slaDeadline:                e.slaDeadline     || null,
  slaElapsedPct:              slaElapsed(),
  slaBreach:                  e.slaBreach       || false,
  slaLabel:                   pm.slaLabel,
  intent:                     e.intent,
  sentiment:                  e.sentiment,
  domainCategory:             e.domainCategory,
  domainSubcategory:          e.domainSubcategory || '',
  senderTier:                 e.senderTier,
  isVIP:                      e.isVIP           || false,
  isInternal:                 e.isInternal      || false,

  // Intelligence
  emailSummary:               e.emailSummary    || e.subject,
  classificationReason:       e.classificationReason || '',
  keyQuote:                   e.keyQuote        || null,
  actionItems:                e.actionItems     || [],
  keyDeadlines:               e.keyDeadlines    || [],
  keyStakeholders:            e.keyStakeholders || [],
  monetaryAmounts:            e.monetaryAmounts || [],
  referenceNumbers:           e.referenceNumbers|| [],
  detectedDates:              e.detectedDates   || [],
  gmailLabels:                e.gmailLabels     || [],
  scoreLog:                   e.scoreLog        || [],
  overrideLog:                e.overrideLog     || [],
  preliminaryScore:           e.preliminaryScore|| 0,

  // Risk flags
  legalFlag:                  e.legalFlag                 || false,
  regulatoryFlag:             e.regulatoryFlag            || false,
  financialFlag:              e.financialFlag             || false,
  securityFlag:               e.securityFlag              || false,
  hrFlag:                     e.hrFlag                    || false,
  escalationRecommended:      e.escalationRecommended     || false,
  escalateTo:                 e.escalateTo                || null,
  privilegeFlag:              e.privilegeFlag             || false,
  preservationRequired:       e.preservationRequired      || false,
  boardNotificationRequired:  e.boardNotificationRequired || false,
  riskFlags,

  // Draft
  draftReply:                 e.draftReply          || null,
  draftQualityRating:         e.draftQualityRating  || 'NEEDS_REVIEW',
  draftQualityScore:          e.draftQualityScore   || 0,
  draftQualityBadge:          qb,
  draftConfidence:            e.draftConfidence     || 0.5,
  draftFlaggedItems:          e.draftFlaggedItems   || [],
  draftNeedsInputItems:       e.draftNeedsInputItems|| [],
  draftVerifyItems:           e.draftVerifyItems    || [],
  draftWarnings:              e.draftWarnings       || [],
  draftRequiresLegal:         e.draftRequiresLegal  || false,
  draftHasPlaceholders:       e.draftHasPlaceholders|| false,
  draftNeedsInputCount:       e.draftNeedsInputCount|| 0,
  draftVerifyCount:           e.draftVerifyCount    || 0,
  draftWordCount:             e.draftWordCount      || 0,
  draftCommitments:           e.draftCommitments    || [],
  keyCommitments:             e.keyCommitments      || [],
  draftReplySummary:          e.draftReplySummary   || '',
  draftStatus:                e.draftStatus         || 'AWAITING_APPROVAL',
  complianceIssues:           e.complianceIssues    || [],
  shouldDraft:                e.shouldDraft         || false,
  usedFallback:               e.usedFallback        || false,

  // API metadata
  apiModel:    (e.apiModel      || e.draftApiModel   || ''),
  apiCostUSD:  (e.apiCostUSD    || 0) + (e.draftApiCostUSD || 0),

  // Push metadata
  pushKey,
  pushedAt:         new Date().toISOString(),
  processingStatus: 'AWAITING_APPROVAL',
  pipelineVersion:  '4.0',
};

return [{ json: {
  ...e,
  _skipPush:         false,
  _dashboardPayload: JSON.stringify(payload),
  _dashboardUrl:     DASHBOARD_URL,
  _dashboardSecret:  DASHBOARD_SECRET,
  _pushKey:          pushKey,
  _payloadBytes:     JSON.stringify(payload).length,
  _retryAttempt:     0,
  _retryConfig: {
    maxRetries:  MAX_RETRIES,
    baseDelayMs: BASE_DELAY_MS,
    maxDelayMs:  32000,
    backoffExp:  2,
  },
  processingStatus: 'PUSH_BUILDING',
}}];

const raw   = $input.first().json;
const body  = raw.body || raw;

const senderEmail  = (body.senderEmail || '').trim();
const threadId     = (body.threadId    || '').trim();
const messageId    = (body.messageId   || '').trim();

// Real Gmail threadId is a long numeric string, never starts with 'id_'
const hasRealThread  = threadId.length > 10  && !threadId.startsWith('id_');
const hasRealMessage = messageId.length > 10 && !messageId.startsWith('id_');
const hasRealSender  = senderEmail.includes('@') && senderEmail.length > 5;

const canSend = hasRealThread && hasRealSender;
const canReply= hasRealThread && hasRealMessage && hasRealSender;

return [{ json: {
  ...body,
  threadId,
  messageId,
  senderEmail,
  safeReplyTo:  hasRealSender  ? senderEmail : null,
  emailBody:    body.action === 'EDIT_SEND'
    ? (body.editedReply || body.draftReply || '')
    : (body.draftReply  || body.editedReply || ''),
  canSend,
  canReply,
  isDemoEmail:  messageId.startsWith('id_') || !hasRealSender,
  skipReason:   !hasRealSender  ? 'no_sender_email'
              : !hasRealThread  ? 'no_real_thread_id'
              : null,
  _rawHeaders:    raw.headers    || {},
  _executionMode: raw.executionMode || '',
}}];

const e = $input.first().json;

// Skip draft generation for NOISE emails or when shouldDraft = false
if (e.shouldDraft === false || e.priorityClass === 'NOISE') {
  return [{ json: {
    ...e,
    _skipDraft: true,
    _skipReason: 'shouldDraft is false or NOISE priority',
  }}];
}

const modelId     = e.replyModel       || 'anthropic/claude-sonnet-4-5';
const temperature = e.replyTemperature || 0.25;

const requestBody = {
  model:           modelId,
  temperature,
  max_tokens:      2500,
  messages: [
    { role: 'system', content: e.replySystemPrompt || '' },
    { role: 'user',   content: e.replyUserPrompt   || '' },
  ],
  response_format: { type: 'json_object' },
  provider: {
    order:           ['Anthropic', 'OpenAI', 'Google'],
    allow_fallbacks: true,
    data_collection: 'deny',
  },
  transforms: ['middle-out'],
};

const sysTokens  = Math.ceil((e.replySystemPrompt || '').length / 4);
const userTokens = Math.ceil((e.replyUserPrompt   || '').length / 4);

return [{ json: {
  ...e,
  _skipDraft:            false,
  _openRouterBody:       JSON.stringify(requestBody),
  _openRouterUrl:        'https://openrouter.ai/api/v1/chat/completions',
  _selectedModel:        modelId,
  _totalInputTokensEst:  sysTokens + userTokens,
  _requestId:            'rpl_' + (e.messageId || '') + '_' + Date.now(),
  _retryAttempt:         0,
  processingStatus:      'REPLY_REQUEST_BUILT',
}}];

// The HTTP node outputs only the API response.
// We re-attach the original input fields from the upstream node.

const apiResponse = $input.first().json;

// Read original input from the Build Classification Request node
// Change 'Build Classification Request' to whatever your node is named exactly
const original = $('Build Classification Request').first().json;

// Merge: original fields + API response nested under _apiResponse
return [{ json: {
  // All original fields (messageId, threadId, senderEmail, etc.)
  ...original,

  // API response fields (choices, model, usage, etc.)
  // Nested so they do not overwrite original fields
  _apiResponse:    apiResponse.body    || apiResponse,
  _apiStatusCode:  apiResponse.statusCode || 200,
  _apiHeaders:     apiResponse.headers    || {},
}}];

const e = $input.first().json;

// Get labels array — handle all formats
let labels = e.gmailLabels || e.gmail_labels || [];

// If it came through as a string (JSON stringified), parse it
if (typeof labels === 'string') {
  try { labels = JSON.parse(labels); } catch { labels = [labels]; }
}

// Ensure it is an array
if (!Array.isArray(labels)) labels = [labels];

// Deduplicate + remove empty values
const unique = [...new Set(labels.filter(l => l && typeof l === 'string' && l.trim().length > 0))];

// Gmail requires label IDs not names.
// Labels created manually in Gmail get an ID like Label_1234567890
// But labels created via API or n8n can be referenced by name IF they already exist.
// The safest approach: pass each label name separately for Gmail node to look up.

// Clean label names — Gmail label names cannot have certain characters
const cleaned = unique.map(l => l.trim().replace(/[<>]/g, ''));

return [{ json: {
  ...e,
  gmailLabelsClean:  cleaned,
  gmailLabel0:       cleaned[0] || null,
  gmailLabel1:       cleaned[1] || null,
  gmailLabel2:       cleaned[2] || null,
  gmailLabel3:       cleaned[3] || null,
  gmailLabelCount:   cleaned.length,
  gmailLabelsString: cleaned.join(','),
}}];
